import type { LocalisedText } from "../types/content";

export interface TopicHowItWorks {
  body: LocalisedText;
  bullets: LocalisedText[];
}

const l = (en: string, es: string): LocalisedText => ({ en, es });
const h = (en: string, es: string, bullets: Array<[string, string]>): TopicHowItWorks => ({
  body: l(en, es),
  bullets: bullets.map(([bulletEn, bulletEs]) => l(bulletEn, bulletEs))
});

export const topicHowItWorks: Record<string, TopicHowItWorks> = {
  "cybersecurity": h(
    "Cybersecurity works as a continuous management cycle rather than as a collection of isolated tools. An organisation first identifies the services, information and technology it must protect, then studies the threats and failures that could affect them. It designs preventive controls to reduce the chance of an incident, detective controls to reveal abnormal activity, and response and recovery capabilities to limit damage when prevention fails. Evidence from incidents, audits, exercises and operational monitoring is then used to improve the next cycle.\n\nThe technical layer only works when it is connected to decisions: someone must own each asset, approve acceptable risk, fund improvements and verify that controls still operate after systems and business processes change.",
    "La ciberseguridad funciona como un ciclo continuo de gestión, no como una colección de herramientas aisladas. La organización identifica primero los servicios, la información y la tecnología que necesita proteger y, después, estudia las amenazas y los fallos que podrían afectarles. Diseña controles preventivos para reducir la probabilidad de un incidente, controles de detección para descubrir actividad anómala y capacidades de respuesta y recuperación para limitar el daño cuando la prevención falla. Las evidencias obtenidas de incidentes, auditorías, simulacros y monitorización sirven para mejorar el siguiente ciclo.\n\nLa parte técnica solo funciona si está conectada con decisiones: cada activo necesita un responsable, alguien debe aceptar o tratar el riesgo, financiar las mejoras y comprobar que los controles siguen funcionando cuando cambian los sistemas o los procesos de negocio.",
    [
      ["Map critical services, assets, data and dependencies.", "Identificar servicios críticos, activos, datos y dependencias."],
      ["Choose controls according to plausible threats and business impact.", "Elegir controles según amenazas plausibles e impacto en el negocio."],
      ["Monitor, respond, recover and feed lessons back into design.", "Monitorizar, responder, recuperar e incorporar las lecciones al diseño."],
      ["Measure effectiveness instead of assuming that deployed controls work.", "Medir la eficacia en lugar de suponer que los controles desplegados funcionan."]
    ]
  ),
  "risk-fundamentals": h(
    "Cyber risk is analysed by linking an objective to a possible event, the conditions that make that event possible and the consequences that would follow. Analysts estimate likelihood using exposure, threat capability, frequency and existing controls; they estimate impact using operational, financial, legal, safety and reputational effects. The initial or inherent risk is compared with the risk remaining after controls, known as residual risk.\n\nThe result is not a mathematically exact prediction. It is a reasoned decision aid that should state assumptions and uncertainty. Management then chooses to avoid, reduce, transfer or accept the risk and records who owns the decision and when it must be reviewed.",
    "El riesgo cibernético se analiza relacionando un objetivo con un posible suceso, las condiciones que permiten que ocurra y las consecuencias que produciría. La probabilidad se estima a partir de la exposición, la capacidad de la amenaza, la frecuencia y los controles existentes; el impacto se valora según efectos operativos, económicos, legales, de seguridad física y de reputación. El riesgo inicial o inherente se compara con el que queda después de aplicar controles, denominado riesgo residual.\n\nEl resultado no es una predicción matemática exacta, sino una ayuda razonada para decidir que debe dejar claras sus hipótesis e incertidumbres. La dirección elige entonces entre evitar, reducir, transferir o aceptar el riesgo, y registra quién es responsable de la decisión y cuándo debe revisarse.",
    [
      ["Define the objective and the asset or service at stake.", "Definir el objetivo y el activo o servicio en juego."],
      ["Describe a credible threat scenario, not only a vulnerability.", "Describir un escenario de amenaza creíble, no solo una vulnerabilidad."],
      ["Estimate likelihood and impact with explicit evidence and assumptions.", "Estimar probabilidad e impacto con evidencias e hipótesis explícitas."],
      ["Select a treatment and track the remaining risk to an accountable owner.", "Elegir un tratamiento y asignar el riesgo restante a un responsable."]
    ]
  ),
  "security-principles": h(
    "Security principles turn broad goals into repeatable design decisions. Least privilege limits every identity to the minimum permissions needed; need to know restricts information to those who require it; segregation of duties prevents one person from completing a sensitive process alone; and defence in depth places independent barriers at different points. Fail-secure defaults, explicit trust boundaries and secure-by-default configuration support the same idea: a single mistake should not become a complete compromise.\n\nThese principles are applied during architecture, implementation and operation. Teams examine each trust decision, remove unnecessary authority and test what happens when one control, account or component fails.",
    "Los principios de seguridad convierten objetivos generales en decisiones de diseño repetibles. El mínimo privilegio limita cada identidad a los permisos imprescindibles; la necesidad de saber restringe la información a quien la requiere; la segregación de funciones evita que una sola persona complete un proceso sensible; y la defensa en profundidad coloca barreras independientes en distintos puntos. Los valores predeterminados seguros, los límites de confianza explícitos y la configuración segura por defecto persiguen la misma idea: un único error no debería provocar un compromiso total.\n\nEstos principios se aplican durante la arquitectura, la implantación y la operación. Los equipos revisan cada decisión de confianza, eliminan autoridad innecesaria y prueban qué ocurre cuando falla un control, una cuenta o un componente.",
    [
      ["Grant only the permissions required for a defined task.", "Conceder únicamente los permisos necesarios para una tarea definida."],
      ["Separate approval, execution and review of sensitive actions.", "Separar aprobación, ejecución y revisión de acciones sensibles."],
      ["Place independent controls before, during and after an attack path.", "Situar controles independientes antes, durante y después de una ruta de ataque."],
      ["Design failure states so that they do not silently grant more access.", "Diseñar los estados de fallo para que no concedan más acceso de forma silenciosa."]
    ]
  ),
  "zero-trust": h(
    "Zero Trust replaces implicit trust based on network location with explicit decisions about each access request. A policy engine evaluates the identity, device health, requested resource, sensitivity, behaviour, location and other context. A policy enforcement point then permits, denies or limits the connection, often requiring stronger authentication or a shorter session when risk is higher. Access is scoped to a specific resource rather than to an entire internal network.\n\nThe decision is not permanent. Session activity, device posture and threat intelligence can trigger re-evaluation, token revocation or additional controls. Implementing Zero Trust therefore requires reliable identities, an accurate asset inventory, segmented resources, useful telemetry and policies that can actually be enforced.",
    "Zero Trust sustituye la confianza implícita basada en la ubicación de red por decisiones explícitas para cada solicitud de acceso. Un motor de políticas evalúa la identidad, el estado del dispositivo, el recurso solicitado, su sensibilidad, el comportamiento, la ubicación y otros datos de contexto. Un punto de aplicación permite, deniega o limita la conexión, y puede exigir autenticación reforzada o una sesión más corta cuando el riesgo es mayor. El acceso se limita a un recurso concreto en vez de abrir una red interna completa.\n\nLa decisión no es permanente. La actividad de la sesión, el estado del dispositivo o la inteligencia de amenazas pueden provocar una reevaluación, la revocación de un token o controles adicionales. Por eso Zero Trust necesita identidades fiables, inventario preciso, recursos segmentados, telemetría útil y políticas que puedan aplicarse de verdad.",
    [
      ["Identify the exact resource and action being requested.", "Identificar el recurso y la acción exactos que se solicitan."],
      ["Evaluate identity, device and contextual risk before access.", "Evaluar identidad, dispositivo y riesgo contextual antes del acceso."],
      ["Enforce the least privilege through resource-level policy.", "Aplicar mínimo privilegio mediante políticas a nivel de recurso."],
      ["Reassess trust during the session and revoke access when conditions change.", "Reevaluar la confianza durante la sesión y revocar el acceso si cambian las condiciones."]
    ]
  ),
  "threat-modelling": h(
    "Threat modelling begins by drawing the system as it really exchanges data: users, services, databases, external dependencies, entry points and trust boundaries. The team identifies valuable assets and asks how each component or data flow could be spoofed, altered, disclosed, interrupted or abused. The resulting threats are ranked by feasibility and impact, then linked to design changes, controls or accepted assumptions.\n\nThe model is updated when architecture changes, not filed away after a workshop. Its value lies in exposing hidden assumptions early—for example, that an internal service is trustworthy, that an update channel cannot be altered or that a user cannot reach an administrative function.",
    "El modelado de amenazas comienza representando cómo intercambia datos el sistema de verdad: usuarios, servicios, bases de datos, dependencias externas, puntos de entrada y límites de confianza. El equipo identifica los activos valiosos y pregunta de qué manera cada componente o flujo podría suplantarse, alterarse, revelarse, interrumpirse o utilizarse indebidamente. Las amenazas resultantes se priorizan por viabilidad e impacto y se relacionan con cambios de diseño, controles o supuestos aceptados.\n\nEl modelo se actualiza cuando cambia la arquitectura, no se archiva tras un taller. Su valor está en descubrir supuestos ocultos con antelación: por ejemplo, creer que un servicio interno es fiable, que un canal de actualización no puede manipularse o que un usuario no puede alcanzar una función administrativa.",
    [
      ["Diagram components, data flows, entry points and trust boundaries.", "Representar componentes, flujos de datos, puntos de entrada y límites de confianza."],
      ["List assets and plausible misuse or failure cases.", "Enumerar activos y casos plausibles de abuso o fallo."],
      ["Prioritise threats by feasibility and consequence.", "Priorizar amenazas por viabilidad y consecuencia."],
      ["Record mitigations, owners and assumptions that require validation.", "Registrar mitigaciones, responsables y supuestos que deben validarse."]
    ]
  ),
  "exposure-management": h(
    "Exposure management continuously joins several views that are often kept separate: asset inventory, vulnerabilities, identity permissions, internet reachability, cloud configuration, attack-path analysis and current threat activity. A finding becomes more urgent when an attacker can reach it, exploit it, move from it towards a critical asset and bypass or evade existing controls. This is why a lower-severity weakness on an exposed identity server may matter more than a high score on an isolated test machine.\n\nTeams validate priority items, assign remediation to the correct owner and re-scan or test after changes. Trends such as time to remove exposure, recurrence and concentration around critical services show whether the programme is improving.",
    "La gestión de la exposición combina de forma continua varias perspectivas que suelen estar separadas: inventario de activos, vulnerabilidades, permisos de identidad, alcance desde Internet, configuración de nube, análisis de rutas de ataque y actividad actual de las amenazas. Un hallazgo es más urgente cuando un atacante puede alcanzarlo, explotarlo, avanzar desde él hacia un activo crítico y eludir los controles existentes. Por eso una debilidad de gravedad moderada en un servidor de identidad expuesto puede importar más que una puntuación alta en una máquina de pruebas aislada.\n\nLos equipos validan los elementos prioritarios, asignan la corrección al responsable adecuado y vuelven a comprobar el sistema después del cambio. El tiempo de eliminación, la recurrencia y la concentración de exposición alrededor de servicios críticos indican si el programa mejora.",
    [
      ["Discover assets, identities, services and external attack surface continuously.", "Descubrir continuamente activos, identidades, servicios y superficie externa."],
      ["Combine severity with reachability, exploitability and business importance.", "Combinar gravedad con alcanzabilidad, explotabilidad e importancia para el negocio."],
      ["Trace attack paths to determine where one fix removes several risks.", "Trazar rutas de ataque para localizar correcciones que eliminen varios riesgos."],
      ["Verify remediation and measure how quickly exposure returns or disappears.", "Verificar la corrección y medir con qué rapidez reaparece o desaparece la exposición."]
    ]
  ),
  "malware": h(
    "Malware normally passes through a chain of stages. It first reaches a system through a malicious attachment, compromised website, stolen account, vulnerable service, removable device or poisoned software package. An initial loader or script then executes, checks the environment and may download additional modules. To remain useful to the attacker, the code often creates persistence, raises privileges, disables security tools, steals credentials and communicates with command-and-control infrastructure.\n\nWhat happens next depends on the family: spyware collects information, a banking trojan alters transactions, a worm spreads automatically, a rootkit hides activity and destructive malware corrupts data or systems. Defenders therefore examine behaviour and relationships between events, not just filenames or a single antivirus alert.",
    "El malware suele avanzar mediante una cadena de etapas. Primero llega al sistema a través de un adjunto malicioso, una web comprometida, una cuenta robada, un servicio vulnerable, un dispositivo extraíble o un paquete de software manipulado. Después se ejecuta un cargador o script, comprueba el entorno y puede descargar módulos adicionales. Para seguir siendo útil al atacante, el código suele establecer persistencia, elevar privilegios, desactivar herramientas de seguridad, robar credenciales y comunicarse con infraestructura de mando y control.\n\nLo que ocurre después depende de la familia: el software espía recopila información, un troyano bancario altera transacciones, un gusano se propaga por sí mismo, un rootkit oculta actividad y el malware destructivo corrompe datos o sistemas. Por eso la defensa analiza comportamientos y relaciones entre eventos, no solo nombres de archivo o una alerta aislada del antivirus.",
    [
      ["Initial access delivers or triggers the malicious code.", "El acceso inicial entrega o activa el código malicioso."],
      ["Execution, persistence and privilege escalation establish control.", "La ejecución, la persistencia y la elevación de privilegios consolidan el control."],
      ["Credential theft and lateral movement expand the compromise.", "El robo de credenciales y el movimiento lateral amplían el compromiso."],
      ["Command-and-control and payload actions achieve the attacker's objective.", "El mando y control y las acciones de la carga útil cumplen el objetivo del atacante."]
    ]
  ),
  "ransomware": h(
    "Modern ransomware is usually an intrusion followed by extortion, not merely a program that encrypts one computer. Attackers obtain access through stolen credentials, phishing, exposed remote services or a supplier. They explore the environment, steal additional credentials, identify high-value systems, disable monitoring and try to reach backup administration. Many groups exfiltrate sensitive data before encryption so that they can threaten publication even if recovery is possible.\n\nThe disruptive phase is deliberately coordinated: files, virtual machines or management servers may be encrypted at the same time, while recovery tools and shadow copies are deleted. The victim then faces several decisions at once—containment, continuity, legal notification, communications, evidence preservation and clean restoration.",
    "El ransomware moderno suele ser una intrusión seguida de extorsión, no simplemente un programa que cifra un ordenador. Los atacantes acceden mediante credenciales robadas, phishing, servicios remotos expuestos o un proveedor. Exploran el entorno, obtienen más credenciales, localizan sistemas valiosos, desactivan la monitorización e intentan alcanzar la administración de las copias de seguridad. Muchos grupos extraen datos sensibles antes del cifrado para amenazar con publicarlos aunque la recuperación sea posible.\n\nLa fase disruptiva se coordina de forma deliberada: pueden cifrarse a la vez ficheros, máquinas virtuales o servidores de gestión, mientras se eliminan herramientas de recuperación y copias instantáneas. La víctima debe tomar simultáneamente decisiones de contención, continuidad, notificación legal, comunicación, conservación de pruebas y restauración limpia.",
    [
      ["Gain an initial foothold and expand administrative access.", "Obtener un punto de entrada y ampliar el acceso administrativo."],
      ["Discover valuable data, backups and operational dependencies.", "Localizar datos valiosos, copias y dependencias operativas."],
      ["Exfiltrate information and weaken defensive or recovery systems.", "Extraer información y debilitar sistemas defensivos o de recuperación."],
      ["Encrypt or disrupt at scale, then apply financial and reputational pressure.", "Cifrar o interrumpir a escala y ejercer presión económica y reputacional."]
    ]
  ),
  "phishing-social-engineering": h(
    "Social engineering works by making a false request look compatible with a person's normal duties. The attacker researches roles, suppliers, current projects and communication habits, then creates urgency, authority, fear or curiosity. The request may ask the victim to open a file, enter credentials into a copied login page, approve an MFA prompt, change bank details, reveal confidential information or bypass a normal procedure.\n\nGood campaigns are interactive. If the first message succeeds, the attacker may continue the conversation from a compromised mailbox, imitate writing style or call the victim to reinforce the story. The most effective defence therefore combines technical filtering with procedures that require independent verification for high-impact actions.",
    "La ingeniería social funciona haciendo que una solicitud falsa parezca compatible con el trabajo habitual de la víctima. El atacante investiga funciones, proveedores, proyectos en curso y formas de comunicación, y después crea urgencia, autoridad, miedo o curiosidad. Puede pedir que se abra un archivo, se introduzcan credenciales en una página copiada, se apruebe una notificación MFA, se cambien datos bancarios, se revele información confidencial o se omita un procedimiento normal.\n\nLas campañas eficaces son interactivas. Si el primer mensaje funciona, el atacante puede continuar la conversación desde un buzón comprometido, imitar el estilo de escritura o llamar por teléfono para reforzar la historia. Por eso la mejor defensa combina filtros técnicos con procedimientos que exigen una verificación independiente para las acciones de mayor impacto.",
    [
      ["Collect context that makes the pretext believable.", "Recopilar contexto que haga creíble el pretexto."],
      ["Create emotional pressure that discourages careful verification.", "Crear presión emocional que desanime una verificación cuidadosa."],
      ["Direct the victim towards a credential, payment or access action.", "Dirigir a la víctima hacia una acción de credenciales, pago o acceso."],
      ["Exploit the resulting account, information or process change.", "Aprovechar la cuenta, la información o el cambio de proceso obtenido."]
    ]
  ),
  "credential-attacks": h(
    "Credential attacks exploit the fact that passwords, tokens and sessions can be guessed, reused, stolen or tricked out of users. In credential stuffing, an attacker tests username-password pairs leaked from another service. Password spraying tries a small set of common passwords against many accounts to avoid lockouts, whereas brute force concentrates many guesses on one account. Adversary-in-the-middle phishing can relay a real login and capture the session cookie even when some forms of MFA are enabled.\n\nOnce a credential works, attackers test its privileges, create persistence, register new authentication methods or steal additional tokens. Detection relies on combining login location, device, timing, failed attempts, impossible travel, token use and post-login behaviour.",
    "Los ataques contra credenciales aprovechan que las contraseñas, los tokens y las sesiones pueden adivinarse, reutilizarse, robarse o conseguirse mediante engaño. En el relleno de credenciales se prueban combinaciones de usuario y contraseña filtradas de otro servicio. La pulverización prueba unas pocas contraseñas frecuentes contra muchas cuentas para evitar bloqueos, mientras que la fuerza bruta concentra numerosos intentos sobre una cuenta. El phishing con intermediario puede retransmitir un inicio de sesión real y capturar la cookie de sesión incluso con ciertas formas de MFA.\n\nCuando una credencial funciona, el atacante comprueba sus privilegios, crea persistencia, registra nuevos métodos de autenticación o roba más tokens. La detección combina ubicación, dispositivo, hora, fallos, viajes imposibles, uso de tokens y comportamiento posterior al inicio de sesión.",
    [
      ["Obtain candidate passwords, tokens or session material.", "Obtener posibles contraseñas, tokens o material de sesión."],
      ["Test them while trying to evade rate limits and lockouts.", "Probarlos intentando eludir límites de frecuencia y bloqueos."],
      ["Use a valid session to enumerate access and establish persistence.", "Usar una sesión válida para enumerar accesos y establecer persistencia."],
      ["Expand privileges or pivot to other accounts and services.", "Ampliar privilegios o saltar a otras cuentas y servicios."]
    ]
  ),
  "network-attacks": h(
    "Network attacks manipulate or abuse the way systems exchange traffic. Reconnaissance identifies reachable addresses, ports and services. Spoofing forges an apparent source, poisoning changes name or address resolution, and interception places the attacker between communicating parties. Denial-of-service attacks exhaust bandwidth, connection tables, application workers or another finite resource. Exploitation of an exposed service can then provide code execution or access to internal systems.\n\nThe same technique has different consequences depending on topology and protocol protections. Encryption can protect content but not always availability or metadata; segmentation limits how far a compromise can travel; and authenticated protocols make impersonation harder. Packet captures, flow records and device logs are combined to reconstruct what actually happened.",
    "Los ataques de red manipulan o abusan de la forma en que los sistemas intercambian tráfico. El reconocimiento identifica direcciones, puertos y servicios accesibles. La suplantación falsifica un origen aparente, el envenenamiento altera la resolución de nombres o direcciones y la interceptación sitúa al atacante entre las partes que se comunican. Los ataques de denegación de servicio agotan ancho de banda, tablas de conexión, procesos de aplicación u otro recurso limitado. La explotación de un servicio expuesto puede proporcionar ejecución de código o acceso a sistemas internos.\n\nLa misma técnica produce consecuencias distintas según la topología y las protecciones del protocolo. El cifrado protege el contenido, pero no siempre la disponibilidad o los metadatos; la segmentación limita la propagación; y los protocolos autenticados dificultan la suplantación. Las capturas de paquetes, los registros de flujo y los registros de dispositivos permiten reconstruir lo sucedido.",
    [
      ["Discover reachable hosts, services and protocol behaviour.", "Descubrir equipos, servicios y comportamiento de protocolos accesibles."],
      ["Manipulate trust, routing, resolution or resource consumption.", "Manipular confianza, enrutamiento, resolución o consumo de recursos."],
      ["Exploit a service or intercept a communication path.", "Explotar un servicio o interceptar una ruta de comunicación."],
      ["Use network visibility to confirm scope and affected flows.", "Usar visibilidad de red para confirmar alcance y flujos afectados."]
    ]
  ),
  "intrusion-behaviours": h(
    "Intrusion behaviour is usually described as a sequence of tactics rather than as one exploit. An attacker gains initial access, runs code, establishes persistence, raises privileges, avoids detection, steals credentials, discovers the environment, moves laterally, collects data and finally exfiltrates or disrupts it. Frameworks such as ATT&CK organise these behaviours so that defenders can compare observations across different tools and incidents.\n\nThe sequence is not always linear: an operator may repeat discovery after each new foothold, use several persistence methods or skip a stage because access was purchased from another criminal. Detection becomes stronger when multiple weak signals are correlated into an attack story instead of treating each event independently.",
    "El comportamiento de una intrusión suele describirse como una secuencia de tácticas, no como una única explotación. El atacante obtiene acceso inicial, ejecuta código, establece persistencia, eleva privilegios, evita la detección, roba credenciales, descubre el entorno, se desplaza lateralmente, recopila datos y finalmente los extrae o interrumpe el servicio. Marcos como ATT&CK organizan estos comportamientos para que los defensores comparen observaciones entre herramientas e incidentes.\n\nLa secuencia no siempre es lineal: un operador puede repetir el descubrimiento tras cada nuevo acceso, utilizar varios métodos de persistencia u omitir una fase porque compró el acceso a otro delincuente. La detección mejora cuando varias señales débiles se correlacionan en una historia de ataque en vez de analizar cada evento por separado.",
    [
      ["Translate raw events into attacker tactics and techniques.", "Traducir eventos sin procesar a tácticas y técnicas del atacante."],
      ["Correlate activity across identity, endpoint, network and cloud sources.", "Correlacionar actividad de identidad, equipos, red y nube."],
      ["Identify the current stage and likely next actions.", "Identificar la fase actual y las acciones probables siguientes."],
      ["Use the observed chain to contain access and improve detections.", "Usar la cadena observada para contener el acceso y mejorar detecciones."]
    ]
  ),
  "threat-actors": h(
    "Threat actors are understood through capability, intent, opportunity and operating style. Financially motivated groups optimise for profit, state-linked operators may prioritise espionage or strategic disruption, hacktivists seek visibility, insiders already possess legitimate access and opportunists exploit whatever is exposed. Analysts build an assessment from infrastructure, malware, targeting, working hours, language, victimology and repeated techniques.\n\nAttribution remains probabilistic because evidence can be copied or deliberately planted. For defence, the useful question is often not the actor's name but which behaviours, access routes and objectives are likely. That assessment guides monitoring priorities, tabletop scenarios and the protection of assets attractive to that type of adversary.",
    "Los actores de amenaza se comprenden mediante su capacidad, intención, oportunidad y forma de operar. Los grupos con motivación económica optimizan el beneficio; los vinculados a Estados pueden priorizar espionaje o interrupción estratégica; los hacktivistas buscan visibilidad; las personas internas ya disponen de acceso legítimo; y los oportunistas explotan lo que encuentran expuesto. El análisis combina infraestructura, malware, selección de víctimas, horarios, idioma y técnicas repetidas.\n\nLa atribución sigue siendo probabilística porque las evidencias pueden copiarse o colocarse deliberadamente. Para defenderse suele ser más útil conocer los comportamientos, vías de acceso y objetivos probables que el nombre del grupo. Esa evaluación orienta la monitorización, los simulacros y la protección de activos atractivos para ese adversario.",
    [
      ["Assess motivation, resources, access and tolerance for risk.", "Evaluar motivación, recursos, acceso y tolerancia al riesgo."],
      ["Compare targeting and tradecraft across several incidents.", "Comparar selección de objetivos y forma de operar entre incidentes."],
      ["Express attribution with confidence levels and alternative explanations.", "Expresar la atribución con niveles de confianza y explicaciones alternativas."],
      ["Convert the assessment into likely scenarios and defensive priorities.", "Convertir la evaluación en escenarios probables y prioridades defensivas."]
    ]
  ),
  "supply-chain-attacks": h(
    "A supply-chain attack reaches a target through a product, supplier or service that the target already trusts. The attacker may compromise a developer account, source repository, build server, package registry, update-signing key, managed-service console or hardware component. Malicious code or access is then distributed through a normal delivery path, potentially affecting many customers at once.\n\nThe attack succeeds because downstream organisations inherit trust they did not create themselves. Detection therefore examines provenance and behaviour: who produced the component, how it was built, whether signatures and hashes match, what changed between versions and what the component does after installation. Segmentation and restricted supplier privileges reduce the impact when inherited trust fails.",
    "Un ataque a la cadena de suministro alcanza al objetivo mediante un producto, proveedor o servicio en el que ya confía. El atacante puede comprometer una cuenta de desarrollo, un repositorio de código, un servidor de compilación, un registro de paquetes, una clave de firma de actualizaciones, la consola de un servicio gestionado o un componente de hardware. El código malicioso o el acceso se distribuyen después por un canal normal, con capacidad para afectar a muchos clientes a la vez.\n\nEl ataque funciona porque las organizaciones heredan una confianza que no han creado. La detección revisa procedencia y comportamiento: quién produjo el componente, cómo se compiló, si coinciden firmas y hashes, qué cambió entre versiones y qué hace tras instalarse. La segmentación y los privilegios limitados de proveedores reducen el impacto cuando esa confianza falla.",
    [
      ["Compromise an upstream development, service or distribution point.", "Comprometer un punto de desarrollo, servicio o distribución previo."],
      ["Insert malicious code, credentials or administrative access.", "Insertar código malicioso, credenciales o acceso administrativo."],
      ["Deliver it through a trusted update or supplier relationship.", "Distribuirlo mediante una actualización o relación de proveedor de confianza."],
      ["Abuse inherited privileges inside downstream environments.", "Abusar de los privilegios heredados en los entornos de los clientes."]
    ]
  ),
  "digital-identity": h(
    "A digital identity is created when an organisation records attributes that distinguish a person, device, workload or partner and links them to one or more credentials. During proofing, the organisation decides how much evidence is required to trust those attributes. The identity is then assigned roles or policies, used to authenticate, monitored during its lifetime and changed when the subject moves role, replaces a device or leaves.\n\nIdentity is therefore a lifecycle, not a username. Errors at any stage create risk: weak proofing admits an impostor, stale attributes grant the wrong access, duplicate accounts hide accountability and delayed revocation leaves an abandoned route into systems.",
    "Una identidad digital se crea cuando una organización registra atributos que distinguen a una persona, dispositivo, carga de trabajo o colaborador y los vincula con una o varias credenciales. Durante la verificación se decide qué evidencias hacen falta para confiar en esos atributos. Después se asignan funciones o políticas, la identidad se utiliza para autenticarse, se monitoriza durante su vida útil y se modifica cuando cambia el puesto, se sustituye un dispositivo o termina la relación.\n\nLa identidad es, por tanto, un ciclo de vida y no solo un nombre de usuario. Un fallo en cualquier fase crea riesgo: una verificación débil admite a un impostor, atributos desactualizados conceden acceso incorrecto, cuentas duplicadas ocultan la responsabilidad y una revocación tardía mantiene una vía abandonada hacia los sistemas.",
    [
      ["Establish identity attributes with evidence appropriate to the risk.", "Establecer atributos de identidad con evidencias acordes al riesgo."],
      ["Issue credentials and connect the identity to access policies.", "Emitir credenciales y vincular la identidad con políticas de acceso."],
      ["Update roles, devices and attributes when circumstances change.", "Actualizar funciones, dispositivos y atributos cuando cambian las circunstancias."],
      ["Disable and revoke every related account, token and secret at end of life.", "Deshabilitar y revocar todas las cuentas, tokens y secretos al final del ciclo."]
    ]
  ),
  "authentication-authorisation": h(
    "Authentication answers who or what is making a request; authorisation answers whether that identity may perform the requested action on the requested resource. A login flow validates one or more credentials and creates a session or token. Every protected operation should then evaluate permissions, role, attributes, resource ownership and contextual restrictions before allowing it.\n\nThe two controls must remain separate. A strongly authenticated user may still be forbidden to read payroll data, and a perfectly designed permission rule is useless if an attacker can steal the session. Applications must also enforce decisions on the server side, because hiding a button in the interface does not prevent a direct API request.",
    "La autenticación responde quién o qué realiza una solicitud; la autorización determina si esa identidad puede ejecutar la acción solicitada sobre ese recurso. El inicio de sesión valida una o varias credenciales y crea una sesión o token. Cada operación protegida debe evaluar después permisos, función, atributos, propiedad del recurso y restricciones de contexto antes de permitirla.\n\nAmbos controles deben mantenerse separados. Un usuario autenticado con gran solidez puede seguir sin permiso para leer nóminas, y una regla de permisos perfecta no sirve si el atacante roba la sesión. Además, las aplicaciones deben aplicar las decisiones en el servidor, porque ocultar un botón en la interfaz no impide una petición directa a la API.",
    [
      ["Verify the claimant with credentials and an appropriate assurance level.", "Verificar al solicitante con credenciales y un nivel de garantía adecuado."],
      ["Create a bounded session with expiry and revocation controls.", "Crear una sesión limitada con caducidad y revocación."],
      ["Evaluate permission for each sensitive resource and action.", "Evaluar el permiso para cada recurso y acción sensibles."],
      ["Log decisions so that access can be reviewed and investigated.", "Registrar las decisiones para poder revisar e investigar el acceso."]
    ]
  ),
  "modern-authentication": h(
    "Multi-factor authentication combines independent evidence, such as something the user knows, possesses or is. Its strength depends on the factor and the ceremony: a one-time code can still be phished, whereas a passkey or hardware security key uses public-key cryptography and binds the response to the legitimate site. The private key remains on the device, and the service verifies a signed challenge rather than receiving a reusable password.\n\nA complete design also covers enrolment, device replacement, account recovery and fallback. Attackers often target these weaker routes, persuade support staff to reset a factor or flood a user with approval prompts. Recovery therefore needs an assurance level comparable to normal sign-in.",
    "La autenticación multifactor combina evidencias independientes, como algo que el usuario sabe, posee o es. Su solidez depende del factor y del proceso: un código de un solo uso todavía puede capturarse mediante phishing, mientras que una passkey o llave de seguridad usa criptografía de clave pública y vincula la respuesta al sitio legítimo. La clave privada permanece en el dispositivo y el servicio verifica un reto firmado en vez de recibir una contraseña reutilizable.\n\nUn diseño completo incluye alta, sustitución de dispositivos, recuperación de cuenta y métodos alternativos. Los atacantes suelen dirigirse a esas rutas más débiles, engañar al soporte para restablecer un factor o saturar al usuario con solicitudes de aprobación. La recuperación necesita, por tanto, un nivel de garantía comparable al acceso normal.",
    [
      ["Enrol a trusted authenticator after reliable identity proofing.", "Registrar un autenticador de confianza tras verificar bien la identidad."],
      ["Use phishing-resistant, origin-bound cryptography where possible.", "Usar criptografía resistente al phishing y vinculada al origen cuando sea posible."],
      ["Protect recovery and factor-reset procedures from social engineering.", "Proteger la recuperación y el restablecimiento de factores frente a ingeniería social."],
      ["Detect repeated prompts, new authenticators and unusual session creation.", "Detectar avisos repetidos, nuevos autenticadores y creación anómala de sesiones."]
    ]
  ),
  "federation-sso": h(
    "In federation, an identity provider authenticates the user and sends a signed assertion or token to an application that trusts it. With SAML, the browser carries an assertion to the service provider; with OpenID Connect, the application receives identity claims built on OAuth flows. Single sign-on reuses this trusted authentication across several applications without giving each application the user's password.\n\nThe trust is governed by configuration: redirect addresses, signing keys, token audience, issuer, claims, expiry and logout behaviour. A mistake can allow a token intended for one application to be accepted by another, create overly broad access from a group claim or leave a session active after the central account is disabled.",
    "En la federación, un proveedor de identidad autentica al usuario y envía una afirmación o token firmado a una aplicación que confía en él. Con SAML, el navegador transporta una afirmación al proveedor de servicio; con OpenID Connect, la aplicación recibe atributos de identidad mediante flujos basados en OAuth. El inicio de sesión único reutiliza esa autenticación fiable entre varias aplicaciones sin entregar a cada una la contraseña del usuario.\n\nLa confianza depende de la configuración: direcciones de redirección, claves de firma, audiencia, emisor, atributos, caducidad y cierre de sesión. Un error puede hacer que una aplicación acepte un token destinado a otra, conceder acceso excesivo mediante un grupo o dejar una sesión activa después de deshabilitar la cuenta central.",
    [
      ["Authenticate at the identity provider and establish a trusted session.", "Autenticar en el proveedor de identidad y establecer una sesión de confianza."],
      ["Issue a signed assertion or token for a specific relying application.", "Emitir una afirmación o token firmado para una aplicación concreta."],
      ["Validate issuer, audience, signature, time and required claims.", "Validar emisor, audiencia, firma, tiempo y atributos necesarios."],
      ["Coordinate revocation, logout and account lifecycle across services.", "Coordinar revocación, cierre de sesión y ciclo de cuenta entre servicios."]
    ]
  ),
  "access-control-models": h(
    "Access-control models provide different ways to turn policy into a decision. Role-based access control assigns permissions to job roles and users to those roles. Attribute-based control evaluates facts about the user, device, resource and context at request time. Discretionary control lets an owner delegate access, while mandatory control applies centrally managed labels that users cannot override.\n\nReal environments often combine them: a role may provide baseline access, an attribute policy may restrict it to managed devices during working hours, and resource ownership may permit a limited share. The design must handle conflicts, inheritance and exceptions predictably; otherwise permissions accumulate and nobody can explain why access was granted.",
    "Los modelos de control de acceso convierten la política en una decisión de distintas formas. El control basado en roles asigna permisos a funciones laborales y usuarios a esas funciones. El basado en atributos evalúa datos del usuario, dispositivo, recurso y contexto en el momento de la solicitud. El discrecional permite que un propietario delegue acceso, mientras que el obligatorio aplica etiquetas centrales que los usuarios no pueden anular.\n\nLos entornos reales suelen combinarlos: un rol concede acceso básico, una política de atributos lo restringe a dispositivos gestionados durante el horario laboral y el propietario puede autorizar una compartición limitada. El diseño debe resolver de forma predecible conflictos, herencias y excepciones; de lo contrario, los permisos se acumulan y nadie puede explicar por qué se concedió el acceso.",
    [
      ["Translate business rules into roles, attributes, labels or ownership rules.", "Traducir reglas de negocio a roles, atributos, etiquetas o reglas de propiedad."],
      ["Evaluate policy at the point where the protected action occurs.", "Evaluar la política en el punto donde se ejecuta la acción protegida."],
      ["Define precedence, inheritance and explicit deny behaviour.", "Definir precedencia, herencia y comportamiento de denegación explícita."],
      ["Review entitlements and remove obsolete roles and exceptions.", "Revisar permisos y retirar roles y excepciones obsoletos."]
    ]
  ),
  "privileged-access": h(
    "Privileged access management places administrative actions behind a controlled workflow. Administrators use a normal account for daily work and request elevation only for a defined task. A vault releases or brokers a credential, a policy checks approval and context, and the session may be proxied, recorded and automatically terminated. Just-in-time access expires after minutes or hours instead of remaining permanently assigned.\n\nThe system also rotates passwords or keys after use, monitors commands and protects emergency accounts for genuine outages. The aim is not merely to store administrator passwords: it is to reduce standing privilege, link every powerful action to an individual and make stolen credentials less reusable.",
    "La gestión de accesos privilegiados sitúa las acciones administrativas detrás de un flujo controlado. Los administradores usan una cuenta normal para el trabajo diario y solicitan elevación solo para una tarea definida. Una bóveda entrega o intermedia una credencial, una política comprueba aprobación y contexto, y la sesión puede pasar por un proxy, grabarse y terminar automáticamente. El acceso justo a tiempo caduca tras minutos u horas en lugar de quedar asignado de forma permanente.\n\nEl sistema también rota contraseñas o claves después de usarlas, monitoriza comandos y protege cuentas de emergencia para interrupciones reales. El objetivo no es solo guardar contraseñas de administración, sino reducir privilegios permanentes, vincular cada acción poderosa con una persona y hacer menos reutilizables las credenciales robadas.",
    [
      ["Separate everyday and administrative identities.", "Separar identidades de uso diario y de administración."],
      ["Approve and grant time-limited privilege for a defined purpose.", "Aprobar y conceder privilegio temporal para una finalidad definida."],
      ["Broker, record and monitor the privileged session.", "Intermediar, registrar y monitorizar la sesión privilegiada."],
      ["Revoke access and rotate exposed credentials when the task ends.", "Revocar el acceso y rotar credenciales expuestas al terminar la tarea."]
    ]
  ),
  "machine-identities-secrets": h(
    "Workloads authenticate to one another with machine identities represented by certificates, keys, service-account tokens or cloud roles. A trusted authority issues the credential after the workload proves what it is and where it is running. The credential is scoped to a service and short lifetime, delivered at runtime rather than embedded in code, and rotated automatically. The receiving service validates both the credential and the requested permission.\n\nSecret management separates encrypted storage from applications and records every retrieval. Dynamic secrets can be created for one connection and then destroyed. This limits the damage of a repository leak, container image disclosure or compromised build log because there is no long-lived shared password to reuse.",
    "Las cargas de trabajo se autentican entre sí mediante identidades de máquina representadas por certificados, claves, tokens de cuentas de servicio o roles de nube. Una autoridad fiable emite la credencial después de que la carga demuestre qué es y dónde se ejecuta. La credencial se limita a un servicio y a una vida corta, se entrega en tiempo de ejecución en vez de incrustarse en el código y se rota automáticamente. El servicio receptor valida tanto la credencial como el permiso solicitado.\n\nLa gestión de secretos separa el almacenamiento cifrado de las aplicaciones y registra cada consulta. Los secretos dinámicos pueden crearse para una sola conexión y destruirse después. Así se reduce el daño de una filtración de repositorio, imagen de contenedor o log de compilación, porque no existe una contraseña compartida de larga duración que reutilizar.",
    [
      ["Give each workload a unique, attestable identity.", "Dar a cada carga de trabajo una identidad única y verificable."],
      ["Issue short-lived credentials with narrowly scoped permissions.", "Emitir credenciales de corta duración y permisos muy limitados."],
      ["Inject secrets at runtime and keep them out of source and images.", "Inyectar secretos en ejecución y mantenerlos fuera del código y las imágenes."],
      ["Rotate, revoke and audit credentials automatically.", "Rotar, revocar y auditar credenciales automáticamente."]
    ]
  ),
  "network-fundamentals": h(
    "A network moves data by wrapping it in layers. Applications create messages, transport protocols such as TCP or UDP identify conversations by ports, IP addresses route packets between networks and link-layer technologies deliver frames on the local segment. DNS translates names into addresses, routers choose paths, switches forward local traffic and stateful devices remember active connections.\n\nWhen a user opens a secure website, the device resolves the name, finds a route, establishes a transport connection and negotiates TLS before exchanging HTTP data. Security analysis follows the same path to locate failure: a name may resolve incorrectly, a route may expose traffic, a port may be reachable or the application may accept an unsafe request.",
    "Una red mueve datos encapsulándolos por capas. Las aplicaciones crean mensajes, protocolos de transporte como TCP o UDP identifican conversaciones mediante puertos, las direcciones IP enrutan paquetes entre redes y las tecnologías de enlace entregan tramas en el segmento local. DNS traduce nombres a direcciones, los routers eligen rutas, los switches reenvían tráfico local y los dispositivos con estado recuerdan las conexiones activas.\n\nCuando un usuario abre una web segura, el equipo resuelve el nombre, busca una ruta, establece una conexión de transporte y negocia TLS antes de intercambiar datos HTTP. El análisis de seguridad sigue el mismo recorrido para localizar el fallo: un nombre puede resolverse mal, una ruta puede exponer tráfico, un puerto puede estar accesible o la aplicación puede aceptar una solicitud insegura.",
    [
      ["Resolve a service name to one or more network addresses.", "Resolver el nombre de un servicio a una o varias direcciones de red."],
      ["Route packets and establish a transport-layer conversation.", "Enrutar paquetes y establecer una conversación de transporte."],
      ["Apply encryption and application protocol rules above the connection.", "Aplicar cifrado y reglas del protocolo de aplicación sobre la conexión."],
      ["Use packets, flows and logs to diagnose where communication or trust failed.", "Usar paquetes, flujos y registros para diagnosticar dónde falló la comunicación o la confianza."]
    ]
  ),
  "firewalls-proxies": h(
    "A firewall compares each connection with rules based on source, destination, port, protocol, state and sometimes application or identity. Stateless filtering treats packets individually; a stateful firewall tracks the connection so that response traffic is recognised. Next-generation devices can inspect application patterns, but encrypted traffic limits what they can see unless it is deliberately terminated for inspection.\n\nA forward proxy acts on behalf of clients, while a reverse proxy protects servers. Because the proxy terminates one connection and creates another, it can authenticate users, filter content, enforce HTTP rules, rate-limit requests and hide internal addresses. Its policy must remain narrow: an unrestricted proxy or broad firewall rule can become a convenient route around segmentation.",
    "Un firewall compara cada conexión con reglas basadas en origen, destino, puerto, protocolo, estado y, en algunos casos, aplicación o identidad. El filtrado sin estado trata cada paquete por separado; un firewall con estado sigue la conexión para reconocer el tráfico de respuesta. Los dispositivos avanzados pueden inspeccionar patrones de aplicación, aunque el cifrado limita lo que ven salvo que la conexión se termine expresamente para inspeccionarla.\n\nUn proxy directo actúa en nombre de los clientes y uno inverso protege servidores. Como termina una conexión y crea otra, puede autenticar usuarios, filtrar contenido, aplicar reglas HTTP, limitar peticiones y ocultar direcciones internas. Su política debe ser restrictiva: un proxy abierto o una regla de firewall demasiado amplia pueden convertirse en una ruta cómoda para saltarse la segmentación.",
    [
      ["Define permitted communication paths from business need.", "Definir rutas de comunicación permitidas a partir de necesidades reales."],
      ["Evaluate connection state and relevant application context.", "Evaluar el estado de la conexión y el contexto de aplicación pertinente."],
      ["Terminate or relay traffic where authentication and inspection are required.", "Terminar o retransmitir tráfico cuando se necesiten autenticación e inspección."],
      ["Log denials, exceptions and rule use to remove obsolete access.", "Registrar denegaciones, excepciones y uso de reglas para retirar accesos obsoletos."]
    ]
  ),
  "segmentation": h(
    "Segmentation divides a network into zones with different trust and business purposes, then allows only explicitly required flows between them. Boundaries may be implemented with VLANs, firewalls, cloud security groups, host controls, software-defined policy or microsegmentation around individual workloads. A user workstation, payment environment, production server and industrial controller should not share unrestricted reachability simply because they belong to the same organisation.\n\nEffective segmentation begins with observed dependencies. Teams record which source needs which destination, service and direction, then deny the rest. Testing is essential because an apparently separate zone may still be bridged by shared administration, DNS, identity systems or a dual-homed server.",
    "La segmentación divide una red en zonas con distintos niveles de confianza y finalidades de negocio, y permite únicamente los flujos necesarios entre ellas. Los límites pueden aplicarse mediante VLAN, firewalls, grupos de seguridad en la nube, controles del host, políticas definidas por software o microsegmentación alrededor de cargas individuales. Un puesto de usuario, un entorno de pagos, un servidor de producción y un controlador industrial no deberían tener conectividad libre solo por pertenecer a la misma organización.\n\nUna segmentación eficaz parte de las dependencias observadas. Se registra qué origen necesita qué destino, servicio y dirección, y se deniega lo demás. Es imprescindible probarla porque una zona aparentemente separada puede seguir conectada por administración compartida, DNS, sistemas de identidad o un servidor con interfaces en varias redes.",
    [
      ["Group assets by function, sensitivity and trust level.", "Agrupar activos por función, sensibilidad y nivel de confianza."],
      ["Document the minimum flows required between zones.", "Documentar los flujos mínimos necesarios entre zonas."],
      ["Enforce policy at network and workload boundaries.", "Aplicar la política en límites de red y de carga de trabajo."],
      ["Test lateral paths and shared services that may bypass the design.", "Probar rutas laterales y servicios compartidos que puedan eludir el diseño."]
    ]
  ),
  "secure-remote-access": h(
    "Secure remote access creates an authenticated, encrypted path from an external user or administrator to a limited internal resource. Traditional VPNs extend network connectivity after login, while zero-trust access brokers publish specific applications without placing the device broadly inside the network. Administrative access is often routed through a hardened jump host where commands and sessions can be controlled and recorded.\n\nThe decision should consider user identity, device management, patch level, location and requested resource. Split tunnelling, local malware and stolen session tokens can undermine the encrypted channel, so remote access also requires endpoint protection, short sessions, least privilege and rapid revocation.",
    "El acceso remoto seguro crea una ruta autenticada y cifrada desde un usuario o administrador externo hasta un recurso interno limitado. Las VPN tradicionales amplían la conectividad de red tras el inicio de sesión, mientras que los intermediarios de acceso Zero Trust publican aplicaciones concretas sin introducir el dispositivo de forma amplia en la red. El acceso administrativo suele pasar por un bastión reforzado donde pueden controlarse y registrarse comandos y sesiones.\n\nLa decisión debe considerar identidad del usuario, gestión del dispositivo, nivel de parches, ubicación y recurso solicitado. El túnel dividido, el malware local y el robo de tokens pueden debilitar el canal cifrado, por lo que también hacen falta protección del equipo, sesiones cortas, mínimo privilegio y revocación rápida.",
    [
      ["Authenticate the user and assess the connecting device.", "Autenticar al usuario y evaluar el dispositivo que se conecta."],
      ["Create an encrypted path to a specific approved resource.", "Crear una ruta cifrada hacia un recurso concreto autorizado."],
      ["Broker privileged work through a controlled jump host when needed.", "Intermediar el trabajo privilegiado mediante un bastión controlado cuando sea necesario."],
      ["Monitor the session and revoke it when identity or device risk changes.", "Monitorizar la sesión y revocarla si cambia el riesgo de identidad o dispositivo."]
    ]
  ),
  "network-detection": h(
    "Network detection and response turns packets, flows, DNS activity and protocol metadata into evidence of behaviour. Sensors observe traffic at selected boundaries, decode protocols and create records such as connections, transferred volume, domains, certificates and unusual commands. Analytics compare these records with known indicators, baselines and behavioural models to identify scanning, command-and-control, lateral movement or exfiltration.\n\nAn alert is then enriched with asset and identity context and linked to neighbouring events. Analysts may capture packets for deeper inspection, block a destination, isolate a host or search for the same pattern elsewhere. Placement matters: encrypted, cloud and east-west traffic that never crosses a sensor remains invisible.",
    "La detección y respuesta de red convierte paquetes, flujos, actividad DNS y metadatos de protocolos en evidencias de comportamiento. Los sensores observan tráfico en límites seleccionados, decodifican protocolos y generan registros de conexiones, volumen transferido, dominios, certificados o comandos inusuales. Los análisis comparan esos datos con indicadores conocidos, líneas base y modelos de comportamiento para detectar escaneo, mando y control, movimiento lateral o extracción.\n\nLa alerta se enriquece después con contexto de activos e identidades y se relaciona con eventos cercanos. Los analistas pueden capturar paquetes para profundizar, bloquear un destino, aislar un equipo o buscar el mismo patrón en otros lugares. La ubicación de sensores es decisiva: el tráfico cifrado, de nube o interno que no los atraviesa permanece invisible.",
    [
      ["Collect packet, flow, DNS and protocol telemetry at useful boundaries.", "Recoger telemetría de paquetes, flujos, DNS y protocolos en límites útiles."],
      ["Extract behavioural features and compare them with baselines and detections.", "Extraer rasgos de comportamiento y compararlos con líneas base y detecciones."],
      ["Enrich alerts with asset, identity and threat context.", "Enriquecer alertas con contexto de activos, identidad y amenazas."],
      ["Investigate, contain and hunt for related network activity.", "Investigar, contener y buscar actividad de red relacionada."]
    ]
  ),
  "wireless-network-security": h(
    "Wireless security protects a shared radio medium in which any nearby device can hear transmissions and attempt association. Modern Wi-Fi uses authenticated encryption such as WPA2 or WPA3; enterprise deployments commonly use 802.1X so each user or device authenticates through a central service rather than sharing one password. Access points and controllers also enforce network assignment, client isolation and roaming policy.\n\nThreats include rogue access points, evil twins that imitate a trusted network, weak onboarding, deauthentication abuse and unmanaged devices. Cellular, private 5G and software-defined networks add control-plane identities and virtualised components, but the same questions remain: who may attach, which segment do they enter and how is anomalous radio or network behaviour detected?",
    "La seguridad inalámbrica protege un medio de radio compartido en el que cualquier dispositivo cercano puede escuchar transmisiones e intentar asociarse. El Wi-Fi moderno utiliza cifrado autenticado como WPA2 o WPA3; en entornos empresariales se suele usar 802.1X para que cada usuario o dispositivo se autentique ante un servicio central en lugar de compartir una contraseña. Los puntos de acceso y controladores aplican además asignación de red, aislamiento entre clientes y políticas de itinerancia.\n\nEntre las amenazas están los puntos de acceso no autorizados, redes gemelas que imitan a la legítima, procesos de alta débiles, abuso de desautenticación y dispositivos sin gestionar. Las redes celulares, 5G privadas y definidas por software añaden identidades del plano de control y componentes virtualizados, pero mantienen las mismas preguntas: quién puede conectarse, a qué segmento entra y cómo se detecta actividad anómala.",
    [
      ["Authenticate each user or device before network admission.", "Autenticar cada usuario o dispositivo antes de admitirlo en la red."],
      ["Encrypt radio traffic with current, correctly configured protocols.", "Cifrar el tráfico de radio con protocolos actuales y bien configurados."],
      ["Assign devices to restricted segments according to identity and posture.", "Asignar dispositivos a segmentos restringidos según identidad y estado."],
      ["Detect rogue infrastructure, impersonation and abnormal association patterns.", "Detectar infraestructura no autorizada, suplantación y asociaciones anómalas."]
    ]
  ),
  "hardening-fundamentals": h(
    "Hardening reduces the number of ways a system can be misused before it enters service. A secure baseline disables unnecessary services, removes default accounts, restricts administrative interfaces, configures logging, protects credentials and applies operating-system and application security settings. The baseline is built from vendor guidance and organisational requirements, then expressed as code or a configuration standard so that it can be repeated.\n\nAfter deployment, scanners and management tools compare the actual state with the approved baseline. Exceptions are documented because some services genuinely need a different setting. Hardening is therefore a maintained state: updates, troubleshooting and new software can silently re-enable features or weaken permissions.",
    "El bastionado reduce las formas en que un sistema puede utilizarse indebidamente antes de entrar en servicio. Una línea base segura deshabilita servicios innecesarios, elimina cuentas predeterminadas, restringe interfaces administrativas, configura registros, protege credenciales y aplica ajustes de seguridad del sistema operativo y las aplicaciones. Se construye con guías del fabricante y requisitos de la organización y se expresa como código o estándar para poder repetirla.\n\nTras el despliegue, herramientas de gestión y análisis comparan el estado real con la línea base aprobada. Las excepciones se documentan porque algunos servicios necesitan ajustes diferentes. Por tanto, el bastionado es un estado que debe mantenerse: las actualizaciones, la resolución de averías o el software nuevo pueden reactivar funciones o debilitar permisos sin que resulte evidente.",
    [
      ["Start from a minimal, supported operating image.", "Partir de una imagen mínima y con soporte."],
      ["Apply a documented baseline for services, accounts, permissions and logging.", "Aplicar una línea base documentada para servicios, cuentas, permisos y registros."],
      ["Test that security settings do not break the required function.", "Probar que los ajustes de seguridad no impiden la función necesaria."],
      ["Continuously detect and correct deviations from the approved state.", "Detectar y corregir continuamente desviaciones del estado aprobado."]
    ]
  ),
  "patch-vulnerability-management": h(
    "Vulnerability management begins by discovering assets and matching their software versions and configurations with known weaknesses. A scanner result is validated and enriched with exploit availability, internet exposure, privileges required, asset criticality and compensating controls. This produces a remediation priority rather than a queue sorted only by a numerical severity score.\n\nPatching then follows a controlled path: obtain the update from a trusted source, test compatibility, schedule deployment, monitor failures and verify the installed version. When a patch cannot be applied promptly, teams may disable a feature, restrict access, add detection or isolate the system. The finding is closed only after evidence confirms that the exploitable condition is gone.",
    "La gestión de vulnerabilidades comienza descubriendo activos y relacionando versiones y configuraciones con debilidades conocidas. El resultado de un escáner se valida y se enriquece con disponibilidad de exploits, exposición a Internet, privilegios necesarios, criticidad del activo y controles compensatorios. Así se obtiene una prioridad de corrección, no una cola ordenada únicamente por una puntuación numérica.\n\nEl parcheado sigue después una ruta controlada: obtener la actualización de una fuente fiable, probar compatibilidad, programar el despliegue, vigilar fallos y verificar la versión instalada. Si el parche no puede aplicarse pronto, se puede deshabilitar una función, restringir acceso, añadir detección o aislar el sistema. El hallazgo solo se cierra cuando hay evidencias de que la condición explotable ha desaparecido.",
    [
      ["Maintain an accurate inventory of software, versions and ownership.", "Mantener un inventario preciso de software, versiones y responsables."],
      ["Prioritise using exposure, exploitability and business consequence.", "Priorizar según exposición, explotabilidad y consecuencia para el negocio."],
      ["Test and deploy patches through controlled change management.", "Probar y desplegar parches mediante una gestión controlada del cambio."],
      ["Re-scan or inspect the system to verify remediation.", "Volver a analizar o inspeccionar el sistema para verificar la corrección."]
    ]
  ),
  "endpoint-hardening": h(
    "Endpoint hardening protects laptops and workstations where users browse, read email, open documents and run business software. The operating system is configured to use secure boot, disk encryption, automatic updates, screen locking and restricted local administration. Application control limits which binaries and scripts may execute, while endpoint detection observes processes, command lines, persistence changes and suspicious memory activity.\n\nThe browser, office suite and scripting engines receive special attention because they process untrusted content. Data controls separate corporate information from personal use, and device management can quarantine a machine that is outdated, rooted or no longer assigned to an employee. The goal is to make one malicious click difficult to turn into durable administrative control.",
    "El bastionado de equipos protege portátiles y puestos de trabajo donde los usuarios navegan, leen correo, abren documentos y ejecutan software empresarial. El sistema se configura con arranque seguro, cifrado de disco, actualizaciones automáticas, bloqueo de pantalla y administración local restringida. El control de aplicaciones limita qué binarios y scripts pueden ejecutarse, mientras la detección del equipo observa procesos, líneas de comandos, cambios de persistencia y actividad sospechosa en memoria.\n\nEl navegador, la suite ofimática y los motores de scripts requieren atención especial porque procesan contenido no fiable. Los controles de datos separan información corporativa y uso personal, y la gestión de dispositivos puede poner en cuarentena un equipo desactualizado, con acceso root no autorizado o ya no asignado. El objetivo es impedir que un clic malicioso se convierta fácilmente en control administrativo persistente.",
    [
      ["Enrol the device in central management before granting access.", "Registrar el dispositivo en la gestión central antes de darle acceso."],
      ["Remove local privilege and restrict execution to trusted software.", "Eliminar privilegios locales y limitar la ejecución a software de confianza."],
      ["Protect storage, browser, documents and scripting surfaces.", "Proteger almacenamiento, navegador, documentos y superficies de scripting."],
      ["Detect malicious behaviour and isolate compromised endpoints quickly.", "Detectar comportamiento malicioso y aislar equipos comprometidos con rapidez."]
    ]
  ),
  "server-hardening": h(
    "Server hardening starts with a minimal role: a database server should not also expose unused web, file-sharing or remote-management services. Administrators configure secure protocols, host firewalls, file permissions, service accounts, audit policy and time synchronisation, then protect the management path with strong authentication and restricted source networks. Windows and Linux use different mechanisms, but both require controlled privilege and reliable logs.\n\nWorkloads run under dedicated low-privilege identities, secrets are kept outside configuration files and security updates follow a defined maintenance process. Integrity monitoring and configuration checks reveal unauthorised changes. Because servers often support many users, a small baseline error can have a much larger blast radius than the same error on one workstation.",
    "El bastionado de servidores parte de una función mínima: un servidor de base de datos no debería exponer además servicios web, de archivos o de administración que no utiliza. Se configuran protocolos seguros, firewall del host, permisos de ficheros, cuentas de servicio, auditoría y sincronización horaria, y se protege la vía administrativa con autenticación fuerte y redes de origen restringidas. Windows y Linux usan mecanismos distintos, pero ambos necesitan privilegios controlados y registros fiables.\n\nLas cargas se ejecutan con identidades dedicadas de bajo privilegio, los secretos se mantienen fuera de los ficheros de configuración y las actualizaciones siguen un proceso de mantenimiento. La monitorización de integridad y las comprobaciones de configuración revelan cambios no autorizados. Como los servidores dan servicio a muchos usuarios, un pequeño error de línea base puede tener un radio de impacto muy grande.",
    [
      ["Install only the packages and roles required by the service.", "Instalar solo los paquetes y funciones necesarios para el servicio."],
      ["Restrict management interfaces, service accounts and file permissions.", "Restringir interfaces de administración, cuentas de servicio y permisos de ficheros."],
      ["Enable tamper-resistant audit and integrity monitoring.", "Activar auditoría resistente a manipulaciones y monitorización de integridad."],
      ["Patch, back up and test restoration as part of normal operation.", "Parchear, copiar y probar la restauración como parte de la operación normal."]
    ]
  ),
  "platform-hardening": h(
    "Virtual machines and containers share physical or kernel resources, so platform hardening protects both the guest and the layer that isolates it. Hypervisors are patched and administered from restricted networks; VM templates remove unnecessary devices and services. Container images use minimal base layers, fixed versions, non-root users and read-only filesystems, and are scanned before admission.\n\nAt runtime, orchestrators apply resource limits, seccomp or similar syscall restrictions, capability removal and network policy. The host kernel and container runtime remain part of the trust boundary: a perfectly hardened container cannot compensate for a vulnerable or openly administered host. Image signing and admission policy ensure that only approved artefacts reach production.",
    "Las máquinas virtuales y los contenedores comparten recursos físicos o del núcleo, por lo que el bastionado debe proteger tanto la carga como la capa que la aísla. Los hipervisores se parchean y administran desde redes restringidas; las plantillas de máquinas eliminan dispositivos y servicios innecesarios. Las imágenes de contenedor utilizan bases mínimas, versiones fijadas, usuarios sin root y sistemas de ficheros de solo lectura, y se analizan antes de admitirse.\n\nEn ejecución, los orquestadores aplican límites de recursos, restricciones de llamadas al sistema, retirada de capacidades y políticas de red. El núcleo del host y el entorno de ejecución siguen dentro del límite de confianza: un contenedor bien bastionado no compensa un host vulnerable o administrado abiertamente. La firma de imágenes y las políticas de admisión garantizan que solo lleguen artefactos aprobados a producción.",
    [
      ["Harden and isolate the hypervisor or container host.", "Bastionar y aislar el hipervisor o el host de contenedores."],
      ["Build minimal, immutable and signed workload images.", "Construir imágenes de carga mínimas, inmutables y firmadas."],
      ["Drop unnecessary privileges, capabilities and writable paths.", "Eliminar privilegios, capacidades y rutas de escritura innecesarios."],
      ["Enforce admission, network and runtime policy continuously.", "Aplicar continuamente políticas de admisión, red y ejecución."]
    ]
  ),
  "configuration-management": h(
    "Configuration management defines the desired state of systems in version-controlled templates or policy and then compares that desired state with reality. Automation deploys approved settings consistently, while agents, cloud APIs or scanners report drift such as an opened port, disabled log source, changed encryption setting or manually created administrator.\n\nNot every difference is malicious, so the workflow records who changed what, why and for how long. Safe systems may automatically restore the baseline; sensitive systems may create a review ticket to avoid disrupting service. Version history also makes rollback possible and allows teams to test changes before they affect thousands of assets.",
    "La gestión de configuración define el estado deseado de los sistemas en plantillas o políticas con control de versiones y lo compara después con la realidad. La automatización despliega ajustes aprobados de forma coherente, mientras agentes, API de nube o escáneres informan de desviaciones como un puerto abierto, una fuente de registros desactivada, un ajuste de cifrado modificado o un administrador creado manualmente.\n\nNo toda diferencia es maliciosa, por lo que el flujo registra quién cambió qué, por qué y durante cuánto tiempo. Los sistemas seguros pueden restaurar automáticamente la línea base; los más sensibles pueden generar una revisión para evitar interrumpir el servicio. El historial de versiones permite además volver atrás y probar los cambios antes de afectar a miles de activos.",
    [
      ["Express approved configuration as versioned code or policy.", "Expresar la configuración aprobada como código o política versionados."],
      ["Deploy the same baseline through automated, repeatable tooling.", "Desplegar la misma línea base con herramientas automatizadas y repetibles."],
      ["Detect drift and distinguish authorised exceptions from unknown changes.", "Detectar desviaciones y distinguir excepciones autorizadas de cambios desconocidos."],
      ["Remediate or roll back safely while preserving an audit trail.", "Corregir o revertir con seguridad conservando una trazabilidad." ]
    ]
  ),
  "cloud-fundamentals": h(
    "Cloud security works through programmable services, identities and policy rather than a fixed physical perimeter. A cloud account or subscription contains networks, storage, workloads, databases and management APIs. Every resource is created with an identity, configuration and set of relationships that can be inspected through the provider's control plane. Security teams use organisation policies, roles, encryption, logging and network controls to set guardrails before teams deploy.\n\nBecause resources can appear and disappear in minutes, manual review alone cannot keep up. Infrastructure as code, policy as code and continuous posture checks prevent or detect risky configurations. The data plane that serves users and the control plane that changes the environment both require protection.",
    "La seguridad en la nube funciona mediante servicios programables, identidades y políticas, no mediante un perímetro físico fijo. Una cuenta o suscripción contiene redes, almacenamiento, cargas, bases de datos y API de administración. Cada recurso se crea con una identidad, una configuración y relaciones que pueden inspeccionarse desde el plano de control del proveedor. Las políticas de organización, roles, cifrado, registros y controles de red establecen límites antes de que los equipos desplieguen.\n\nComo los recursos pueden aparecer y desaparecer en minutos, la revisión manual no basta. La infraestructura como código, la política como código y las comprobaciones continuas de postura previenen o detectan configuraciones de riesgo. Deben protegerse tanto el plano de datos que presta el servicio como el plano de control que modifica el entorno.",
    [
      ["Organise accounts and subscriptions with central guardrails.", "Organizar cuentas y suscripciones con límites centrales."],
      ["Use identity-based least privilege for users and workloads.", "Aplicar mínimo privilegio basado en identidad a usuarios y cargas."],
      ["Deploy networks, data controls and logging through reusable code.", "Desplegar redes, controles de datos y registros mediante código reutilizable."],
      ["Continuously inspect control-plane changes and resource posture.", "Inspeccionar continuamente cambios del plano de control y postura de recursos."]
    ]
  ),
  "shared-responsibility": h(
    "Shared responsibility divides security tasks between the cloud provider and the customer according to the service model. The provider normally protects physical facilities, hardware and core platform operation. The customer remains responsible for identities, data, access policy and configuration; in infrastructure services it also manages the guest operating system and applications, while in software-as-a-service much of the stack is operated by the provider.\n\nThe boundary is specific to each service, not a slogan. Teams must read the service documentation, identify which controls are inherited, configure the controls exposed to them and collect evidence that both sides meet the requirement. A provider capability does nothing until the customer enables and governs it correctly.",
    "La responsabilidad compartida reparte las tareas de seguridad entre el proveedor de nube y el cliente según el modelo de servicio. El proveedor suele proteger instalaciones, hardware y operación básica de la plataforma. El cliente sigue siendo responsable de identidades, datos, políticas de acceso y configuración; en infraestructura también gestiona el sistema operativo invitado y las aplicaciones, mientras que en software como servicio gran parte de la pila la opera el proveedor.\n\nEl límite es específico de cada servicio, no un eslogan. Los equipos deben leer la documentación, identificar controles heredados, configurar los que les corresponden y reunir evidencias de que ambas partes cumplen. Una capacidad ofrecida por el proveedor no aporta protección hasta que el cliente la activa y gobierna correctamente.",
    [
      ["Break the service into physical, platform, workload, identity and data layers.", "Dividir el servicio en capas física, plataforma, carga, identidad y datos."],
      ["Assign each security task to provider, customer or both.", "Asignar cada tarea de seguridad al proveedor, al cliente o a ambos."],
      ["Configure and monitor the controls that remain under customer authority.", "Configurar y monitorizar los controles bajo autoridad del cliente."],
      ["Verify inherited controls through contracts, reports and service evidence.", "Verificar controles heredados mediante contratos, informes y evidencias del servicio."]
    ]
  ),
  "cloud-posture-workloads": h(
    "Cloud posture management continuously reads provider APIs to find public storage, excessive permissions, missing encryption, exposed management ports and other deviations from policy. Findings are linked to account, owner, data sensitivity and attack paths so that teams can distinguish a dangerous route to production from a harmless laboratory exception. Preventive policies can block a risky resource before creation.\n\nWorkload protection covers what runs inside virtual machines, containers and serverless functions. It observes processes, packages, network activity and runtime behaviour, scans images and may stop a workload that violates policy. Posture and runtime views complement each other: correct configuration does not prevent application compromise, and endpoint telemetry cannot fix an openly shared storage bucket.",
    "La gestión de postura en la nube consulta continuamente las API del proveedor para detectar almacenamiento público, permisos excesivos, cifrado ausente, puertos de administración expuestos y otras desviaciones. Los hallazgos se relacionan con cuenta, responsable, sensibilidad de datos y rutas de ataque para distinguir una vía peligrosa hacia producción de una excepción inofensiva de laboratorio. Las políticas preventivas pueden bloquear un recurso antes de crearlo.\n\nLa protección de cargas cubre lo que se ejecuta en máquinas virtuales, contenedores y funciones sin servidor. Observa procesos, paquetes, red y comportamiento en ejecución, analiza imágenes y puede detener una carga que infringe la política. Ambas perspectivas se complementan: una configuración correcta no evita que se explote la aplicación, y la telemetría del equipo no corrige un almacenamiento compartido públicamente.",
    [
      ["Collect configuration and relationship data from every cloud account.", "Recoger configuración y relaciones de todas las cuentas de nube."],
      ["Evaluate posture against policy and reachable attack paths.", "Evaluar la postura frente a políticas y rutas de ataque alcanzables."],
      ["Scan workload artefacts before deployment and observe them at runtime.", "Analizar artefactos antes del despliegue y observarlos durante la ejecución."],
      ["Prevent, remediate or isolate resources according to confirmed risk.", "Prevenir, corregir o aislar recursos según el riesgo confirmado."]
    ]
  ),
  "containers-kubernetes": h(
    "Kubernetes accepts a desired state through its API and controllers continually work to make the cluster match it. Security therefore begins at the API server: identities authenticate, role-based policy authorises actions and admission controls inspect objects before they are stored. The scheduler places pods on nodes, the container runtime starts images and network plugins enforce communication policy. Secrets, service accounts and namespaces create additional trust boundaries.\n\nAn attacker who controls a pod may try to read its token, contact the metadata service, mount host paths or ask the API for more resources. Secure clusters use restricted pod security, minimal RBAC, signed images, isolated nodes, network policy and audited control-plane changes. Cluster administration is treated as highly privileged access.",
    "Kubernetes recibe un estado deseado mediante su API y sus controladores trabajan continuamente para que el clúster coincida con él. La seguridad empieza, por tanto, en el servidor de API: las identidades se autentican, las políticas por roles autorizan acciones y los controles de admisión inspeccionan objetos antes de guardarlos. El planificador coloca pods en nodos, el runtime inicia imágenes y los complementos de red aplican políticas de comunicación. Secretos, cuentas de servicio y espacios de nombres crean otros límites de confianza.\n\nUn atacante que controla un pod puede intentar leer su token, contactar con metadatos, montar rutas del host o pedir más recursos a la API. Los clústeres seguros usan seguridad restrictiva de pods, RBAC mínimo, imágenes firmadas, nodos aislados, política de red y auditoría del plano de control. La administración del clúster se trata como acceso altamente privilegiado.",
    [
      ["Authenticate and authorise every Kubernetes API request.", "Autenticar y autorizar cada solicitud a la API de Kubernetes."],
      ["Validate images and workload specifications at admission time.", "Validar imágenes y especificaciones de carga durante la admisión."],
      ["Isolate pods with namespaces, node policy and network controls.", "Aislar pods mediante espacios de nombres, política de nodos y controles de red."],
      ["Monitor runtime and control-plane changes for privilege escalation.", "Monitorizar ejecución y cambios del plano de control para detectar elevación de privilegios."]
    ]
  ),
  "cloud-data-resilience": h(
    "Cloud data protection follows each copy through storage, processing, transfer, backup and deletion. Policies classify the data, choose approved regions and services, encrypt it with provider-managed or customer-controlled keys and restrict access through identities rather than broad network trust. Object versioning, immutability and replication protect against accidental deletion, malicious encryption and regional failure.\n\nResilience is tested by restoring data and rebuilding the service in a clean account or region, not merely by observing that a backup job succeeded. Key availability, cross-account permissions, dependencies and recovery order all matter. Logs of data access and key use provide evidence when a disclosure or destructive action is investigated.",
    "La protección de datos en la nube sigue cada copia durante almacenamiento, tratamiento, transferencia, copia de seguridad y eliminación. Las políticas clasifican el dato, eligen regiones y servicios autorizados, lo cifran con claves del proveedor o controladas por el cliente y restringen el acceso mediante identidades en vez de confianza amplia en la red. El versionado de objetos, la inmutabilidad y la replicación protegen frente a borrado accidental, cifrado malicioso y fallo regional.\n\nLa resiliencia se prueba restaurando datos y reconstruyendo el servicio en una cuenta o región limpia, no solo comprobando que una tarea de copia terminó. Importan la disponibilidad de claves, permisos entre cuentas, dependencias y orden de recuperación. Los registros de acceso a datos y uso de claves aportan evidencias ante una filtración o acción destructiva.",
    [
      ["Classify data and select approved storage locations and services.", "Clasificar datos y elegir ubicaciones y servicios de almacenamiento autorizados."],
      ["Encrypt with governed keys and least-privileged identities.", "Cifrar con claves gobernadas e identidades de mínimo privilegio."],
      ["Create isolated, immutable and geographically appropriate recovery copies.", "Crear copias de recuperación aisladas, inmutables y geográficamente adecuadas."],
      ["Exercise restoration, account rebuild and key recovery end to end.", "Ensayar de extremo a extremo restauración, reconstrucción de cuenta y recuperación de claves."]
    ]
  ),
  "secure-sdlc": h(
    "A secure software development lifecycle adds security decisions to every stage of delivery. During planning, teams define security requirements and abuse cases. During design, they model threats and choose trust boundaries. Developers use approved libraries, secure coding patterns and peer review; automated checks scan code, dependencies, secrets and infrastructure definitions. Before release, the team tests important attack paths and records unresolved risk.\n\nAfter deployment, telemetry, vulnerability reports and incidents feed back into the backlog. The same controls are built into the delivery pipeline so that a dangerous change can be stopped before production. The objective is not to perform one final penetration test, but to make secure behaviour the normal and repeatable route from idea to retirement.",
    "Un ciclo de desarrollo seguro incorpora decisiones de seguridad en cada fase de entrega. Durante la planificación se definen requisitos y casos de abuso. En el diseño se modelan amenazas y se eligen límites de confianza. Los desarrolladores usan bibliotecas aprobadas, patrones de programación segura y revisión entre pares; las comprobaciones automáticas analizan código, dependencias, secretos y definiciones de infraestructura. Antes de publicar, el equipo prueba rutas de ataque importantes y registra el riesgo no resuelto.\n\nTras el despliegue, la telemetría, los informes de vulnerabilidades y los incidentes vuelven a la lista de trabajo. Los mismos controles se integran en la canalización para detener un cambio peligroso antes de producción. El objetivo no es realizar una única prueba de penetración al final, sino convertir la seguridad en la ruta normal y repetible desde la idea hasta la retirada.",
    [
      ["Define security requirements and misuse cases alongside functional needs.", "Definir requisitos de seguridad y casos de abuso junto a las necesidades funcionales."],
      ["Model trust boundaries and risky data flows before implementation.", "Modelar límites de confianza y flujos de datos de riesgo antes de implementar."],
      ["Automate code, dependency, secret and configuration checks in CI/CD.", "Automatizar análisis de código, dependencias, secretos y configuración en CI/CD."],
      ["Use production lessons to improve standards, tests and future designs.", "Usar las lecciones de producción para mejorar estándares, pruebas y diseños futuros."]
    ]
  ),
  "application-testing": h(
    "Application security testing uses several techniques because each sees a different part of the system. Static analysis examines source or compiled code without running it, dynamic analysis sends requests to a live application, interactive testing observes execution from inside the runtime and software composition analysis identifies vulnerable third-party components. Fuzzing supplies unexpected inputs, while manual penetration testing explores chained business-logic flaws that automation often misses.\n\nFindings are triaged by reachability, data exposure, required privileges and realistic impact. Developers reproduce the flaw, fix the root cause and add a regression test. A scanner result is not proof by itself, and a clean scan does not mean the application is secure outside the tested paths.",
    "Las pruebas de seguridad de aplicaciones combinan técnicas porque cada una observa una parte distinta. El análisis estático examina código fuente o compilado sin ejecutarlo; el dinámico envía solicitudes a una aplicación activa; el interactivo observa la ejecución desde el propio entorno; y el análisis de composición identifica componentes de terceros vulnerables. El fuzzing introduce entradas inesperadas y las pruebas manuales exploran cadenas de lógica de negocio que la automatización suele pasar por alto.\n\nLos hallazgos se priorizan según alcanzabilidad, datos expuestos, privilegios necesarios e impacto realista. Los desarrolladores reproducen el fallo, corrigen la causa raíz y añaden una prueba de regresión. Un resultado del escáner no es una prueba por sí solo, y un análisis limpio no garantiza seguridad fuera de las rutas examinadas.",
    [
      ["Select testing methods according to architecture and threat model.", "Elegir métodos de prueba según arquitectura y modelo de amenazas."],
      ["Run automated checks early and repeatedly during development.", "Ejecutar comprobaciones automáticas pronto y de forma repetida."],
      ["Validate important findings manually and explore chained abuse.", "Validar manualmente hallazgos importantes y explorar abusos encadenados."],
      ["Fix the root cause and add a regression test before closure.", "Corregir la causa raíz y añadir una prueba de regresión antes de cerrar."]
    ]
  ),
  "web-security": h(
    "A web application receives untrusted input through URLs, forms, headers, cookies and uploaded files, then uses that input in databases, templates, operating-system commands and business workflows. Security controls validate structure, encode output for the destination context, use parameterised queries and enforce authorisation on every server-side action. Browser protections such as same-origin rules, Content Security Policy and secure cookie attributes reduce script and session abuse.\n\nMany serious flaws arise from broken assumptions rather than missing filters: an object identifier may expose another user's data, a password-reset flow may be bypassed or a purchase price may be altered. Testing therefore follows complete user journeys and checks what happens when steps are reordered, repeated or invoked directly.",
    "Una aplicación web recibe entradas no fiables mediante URL, formularios, cabeceras, cookies y ficheros, y las utiliza después en bases de datos, plantillas, comandos del sistema y procesos de negocio. Los controles validan la estructura, codifican la salida para el contexto de destino, emplean consultas parametrizadas y aplican autorización en cada acción del servidor. Protecciones del navegador como la política de mismo origen, Content Security Policy y atributos seguros de cookies reducen el abuso de scripts y sesiones.\n\nMuchos fallos graves nacen de supuestos rotos y no de filtros ausentes: un identificador puede mostrar datos de otro usuario, un flujo de recuperación puede saltarse o un precio puede modificarse. Por ello se prueban recorridos completos y qué ocurre al reordenar, repetir o invocar directamente cada paso.",
    [
      ["Treat every request field and client-side value as untrusted.", "Tratar cada campo de solicitud y valor del cliente como no fiable."],
      ["Validate input and encode output for its exact execution context.", "Validar entradas y codificar salidas para su contexto exacto de ejecución."],
      ["Enforce object- and action-level authorisation on the server.", "Aplicar autorización de objetos y acciones en el servidor."],
      ["Test complete business workflows, not only individual pages.", "Probar procesos de negocio completos, no solo páginas aisladas."]
    ]
  ),
  "api-session-security": h(
    "An API authenticates a client, validates the requested operation and returns data through a defined contract. Tokens should be issued for a specific audience and scope, expire quickly and be validated for signature, issuer and time. The API then checks object-level and function-level authorisation instead of assuming that possession of a token permits every operation. Input schemas, rate limits and idempotency rules constrain abuse.\n\nSessions connect multiple requests over time. Cookies need secure attributes and protection against cross-site requests; bearer tokens need safe storage and revocation. Gateways can centralise authentication and throttling, but each service must still enforce business permissions because an internal call or forged identifier can bypass a purely perimeter-based rule.",
    "Una API autentica al cliente, valida la operación solicitada y devuelve datos mediante un contrato definido. Los tokens deben emitirse para una audiencia y alcance concretos, caducar pronto y validarse por firma, emisor y tiempo. La API comprueba después autorización a nivel de objeto y función, sin suponer que poseer un token permite cualquier operación. Los esquemas de entrada, límites de frecuencia y reglas de idempotencia restringen el abuso.\n\nLas sesiones conectan varias solicitudes a lo largo del tiempo. Las cookies necesitan atributos seguros y protección frente a solicitudes entre sitios; los tokens al portador requieren almacenamiento seguro y revocación. Una pasarela puede centralizar autenticación y limitación, pero cada servicio debe aplicar los permisos de negocio porque una llamada interna o un identificador falsificado pueden saltarse una regla puramente perimetral.",
    [
      ["Authenticate the caller and validate token audience, scope and lifetime.", "Autenticar al cliente y validar audiencia, alcance y vigencia del token."],
      ["Validate request shape and enforce resource-specific authorisation.", "Validar la forma de la solicitud y aplicar autorización específica del recurso."],
      ["Limit replay, automation and abuse through rate and state controls.", "Limitar repetición, automatización y abuso mediante controles de frecuencia y estado."],
      ["Protect, rotate and revoke sessions when risk or ownership changes.", "Proteger, rotar y revocar sesiones cuando cambian el riesgo o la titularidad."]
    ]
  ),
  "software-supply-chain": h(
    "Software supply-chain security traces how source code becomes a released artefact. Developers authenticate to repositories, changes receive review, build workers run in controlled environments and dependencies are resolved from approved registries. The pipeline generates an inventory such as an SBOM, records provenance and signs the resulting package or image. Deployment systems verify that signature and policy before accepting it.\n\nThe chain must also protect build secrets, runners, package names and update channels. A malicious dependency, stolen maintainer account or modified build script can produce a valid-looking release. Reproducible builds, isolated jobs and independent verification reduce the amount of trust placed in any one person or service.",
    "La seguridad de la cadena de suministro software sigue el recorrido desde el código fuente hasta el artefacto publicado. Los desarrolladores se autentican en repositorios, los cambios se revisan, los trabajadores de compilación se ejecutan en entornos controlados y las dependencias se resuelven desde registros autorizados. La canalización genera un inventario como un SBOM, registra la procedencia y firma el paquete o la imagen. Los sistemas de despliegue verifican firma y política antes de admitirlo.\n\nTambién deben protegerse secretos de compilación, ejecutores, nombres de paquetes y canales de actualización. Una dependencia maliciosa, una cuenta de mantenedor robada o un script modificado pueden crear una versión aparentemente válida. Las compilaciones reproducibles, los trabajos aislados y la verificación independiente reducen la confianza depositada en una sola persona o servicio.",
    [
      ["Protect source repositories, maintainers and branch approval rules.", "Proteger repositorios, mantenedores y reglas de aprobación de ramas."],
      ["Resolve pinned dependencies from trusted and monitored registries.", "Resolver dependencias fijadas desde registros fiables y monitorizados."],
      ["Build in isolated workers and record provenance and component inventory.", "Compilar en trabajadores aislados y registrar procedencia e inventario de componentes."],
      ["Sign artefacts and verify policy again at deployment time.", "Firmar artefactos y volver a verificar la política durante el despliegue."]
    ]
  ),
  "data-lifecycle": h(
    "Data classification assigns a handling level according to sensitivity, legal duty and business consequence. That label follows the information from creation or collection through use, sharing, storage, archive and deletion. Policies translate the label into concrete requirements such as approved locations, access groups, encryption, retention, monitoring and transfer restrictions.\n\nLifecycle controls also reduce unnecessary data. Records are retained only while there is a defined purpose or obligation, then securely deleted from active systems, replicas and backups according to a documented schedule. Discovery and lineage tools help find copies and transformations, because information often loses its original label when exported to spreadsheets, analytics platforms or supplier systems.",
    "La clasificación asigna al dato un nivel de tratamiento según su sensibilidad, obligación legal y consecuencia para el negocio. Esa etiqueta acompaña a la información desde su creación o recogida hasta el uso, compartición, almacenamiento, archivo y eliminación. Las políticas convierten la etiqueta en requisitos concretos de ubicación, grupos de acceso, cifrado, conservación, monitorización y transferencia.\n\nEl ciclo de vida también reduce datos innecesarios. Los registros se conservan solo mientras exista una finalidad u obligación definida y después se eliminan de forma segura de sistemas activos, réplicas y copias conforme a un calendario documentado. Las herramientas de descubrimiento y linaje ayudan a encontrar copias y transformaciones, porque la información suele perder su etiqueta original al exportarse a hojas de cálculo, plataformas analíticas o proveedores.",
    [
      ["Classify information at creation or collection using clear criteria.", "Clasificar la información al crearla o recogerla con criterios claros."],
      ["Apply access, encryption and sharing rules that follow the classification.", "Aplicar reglas de acceso, cifrado y compartición acordes a la clasificación."],
      ["Track copies, transformations and transfers across systems.", "Rastrear copias, transformaciones y transferencias entre sistemas."],
      ["Retain only for a defined purpose and verify secure deletion.", "Conservar solo con una finalidad definida y verificar la eliminación segura."]
    ]
  ),
  "cryptographic-protection": h(
    "Encryption transforms plaintext into ciphertext using a key so that only authorised parties can recover it. Symmetric algorithms use one secret key for efficient bulk protection; asymmetric algorithms use a public-private pair for key exchange, signatures and other trust functions. Hash functions create a fixed-length digest and are one-way, while tokenisation replaces sensitive values with references stored in a controlled mapping system.\n\nThe algorithm is only one part of the design. Keys must be generated with sufficient randomness, stored in protected modules or vaults, rotated, backed up where appropriate and revoked when compromised. Modes, nonces, certificate validation and error handling must be correct, because strong cryptography can be defeated by poor implementation or key management.",
    "El cifrado transforma texto en claro en texto cifrado mediante una clave para que solo las partes autorizadas puedan recuperarlo. Los algoritmos simétricos usan una clave secreta para proteger grandes volúmenes con eficiencia; los asimétricos usan un par público-privado para intercambio de claves, firmas y otras funciones de confianza. Las funciones hash producen un resumen de longitud fija y son unidireccionales, mientras que la tokenización sustituye valores sensibles por referencias guardadas en un sistema controlado.\n\nEl algoritmo es solo una parte. Las claves deben generarse con suficiente aleatoriedad, guardarse en módulos o bóvedas protegidos, rotarse, copiarse cuando corresponda y revocarse si se comprometen. Modos, nonces, validación de certificados y gestión de errores deben ser correctos, porque una criptografía fuerte puede quedar anulada por una implementación o gestión de claves deficientes.",
    [
      ["Choose the primitive according to confidentiality, integrity or pseudonymisation need.", "Elegir la técnica según la necesidad de confidencialidad, integridad o seudonimización."],
      ["Generate and store keys separately from the protected data.", "Generar y guardar claves separadas de los datos protegidos."],
      ["Use authenticated modes, unique nonces and validated libraries.", "Usar modos autenticados, nonces únicos y bibliotecas validadas."],
      ["Rotate, revoke and recover keys through a governed lifecycle.", "Rotar, revocar y recuperar claves mediante un ciclo gobernado."]
    ]
  ),
  "pki-certificates": h(
    "A public key infrastructure binds a public key to an identity through a certificate signed by a trusted certificate authority. A subject creates or receives a key pair, proves control and identity, and obtains a certificate containing names, uses and expiry. During a TLS connection, the peer checks the signature chain, hostname, validity period and revocation status before trusting the public key.\n\nDigital signatures use the private key to sign a digest so that recipients can verify origin and integrity. The infrastructure depends on protecting issuing keys, defining certificate policy, automating renewal and revoking compromised credentials. An expired certificate causes outages, while an incorrectly issued or poorly validated certificate can enable impersonation.",
    "Una infraestructura de clave pública vincula una clave pública con una identidad mediante un certificado firmado por una autoridad de confianza. El titular crea o recibe un par de claves, demuestra control e identidad y obtiene un certificado con nombres, usos y caducidad. Durante una conexión TLS, la otra parte comprueba cadena de firma, nombre, periodo de validez y revocación antes de confiar en la clave pública.\n\nLas firmas digitales usan la clave privada para firmar un resumen, de modo que el receptor verifica origen e integridad. La infraestructura depende de proteger las claves emisoras, definir políticas, automatizar renovaciones y revocar credenciales comprometidas. Un certificado caducado provoca interrupciones, mientras que uno emitido o validado incorrectamente puede permitir suplantación.",
    [
      ["Generate a protected key pair and prove control of the private key.", "Generar un par de claves protegido y demostrar control de la clave privada."],
      ["Issue a certificate under a defined identity and usage policy.", "Emitir un certificado conforme a una política de identidad y uso."],
      ["Validate chain, name, time, purpose and revocation at every connection.", "Validar cadena, nombre, tiempo, finalidad y revocación en cada conexión."],
      ["Automate renewal and revoke immediately after compromise or ownership change.", "Automatizar la renovación y revocar tras compromiso o cambio de titularidad."]
    ]
  ),
  "data-loss-prevention": h(
    "Data loss prevention discovers sensitive content and observes how it moves through endpoints, email, web, cloud storage and network channels. Detection may use exact database matches, document fingerprints, labels, patterns and contextual rules. When a user tries to upload or send matching data, the policy can warn, require justification, encrypt, quarantine or block the action.\n\nDLP is most accurate when classification and business context are reliable. A national identifier pattern alone creates false positives, while encrypted archives and screenshots may evade simple inspection. Programmes therefore tune policies with data owners, distinguish legitimate sharing from exfiltration and investigate repeated or unusual attempts rather than treating every match as malicious.",
    "La prevención de pérdida de datos descubre contenido sensible y observa cómo se mueve por equipos, correo, web, almacenamiento en nube y canales de red. La detección puede usar coincidencias exactas con bases de datos, huellas de documentos, etiquetas, patrones y reglas de contexto. Cuando un usuario intenta subir o enviar datos coincidentes, la política puede advertir, pedir justificación, cifrar, poner en cuarentena o bloquear la acción.\n\nDLP es más preciso cuando la clasificación y el contexto de negocio son fiables. Un patrón de documento de identidad por sí solo genera falsos positivos, mientras que archivos cifrados y capturas pueden eludir una inspección simple. Por eso las políticas se ajustan con propietarios de datos, distinguen compartición legítima de extracción e investigan intentos repetidos o anómalos.",
    [
      ["Discover and classify sensitive data in repositories and endpoints.", "Descubrir y clasificar datos sensibles en repositorios y equipos."],
      ["Inspect content and context when data is copied, sent or uploaded.", "Inspeccionar contenido y contexto cuando se copia, envía o sube información."],
      ["Apply a proportionate action: educate, justify, encrypt, quarantine or block.", "Aplicar una acción proporcionada: informar, justificar, cifrar, aislar o bloquear."],
      ["Tune rules using confirmed incidents, false positives and owner feedback.", "Ajustar reglas con incidentes confirmados, falsos positivos y opinión de responsables."]
    ]
  ),
  "critical-infrastructure": h(
    "Critical-infrastructure cybersecurity connects digital protection with the continued delivery of services such as energy, water, transport, health and communications. Operators identify essential functions, the physical processes and information systems that support them, and the failure modes that could harm people or society. Security controls are selected with safety, availability and recovery constraints in mind, because simply shutting down a vulnerable system may be unacceptable.\n\nThe operating model combines prevention with resilience. Segmented architectures, controlled remote access and monitoring reduce the chance of compromise; manual procedures, spare equipment, mutual aid and tested restoration plans preserve service when technology fails. Public authorities, operators and suppliers also share incident information and coordinate decisions that cross organisational boundaries.",
    "La ciberseguridad de infraestructuras críticas conecta la protección digital con la continuidad de servicios como energía, agua, transporte, sanidad y comunicaciones. Los operadores identifican funciones esenciales, procesos físicos y sistemas de información que las sostienen, así como fallos que podrían dañar a personas o a la sociedad. Los controles se eligen teniendo en cuenta seguridad física, disponibilidad y recuperación, porque apagar sin más un sistema vulnerable puede ser inaceptable.\n\nEl modelo combina prevención y resiliencia. Arquitecturas segmentadas, acceso remoto controlado y monitorización reducen la probabilidad de compromiso; procedimientos manuales, repuestos, ayuda mutua y planes de restauración ensayados mantienen el servicio cuando la tecnología falla. Autoridades, operadores y proveedores comparten además información de incidentes y coordinan decisiones que atraviesan organizaciones.",
    [
      ["Identify essential functions and the digital and physical dependencies behind them.", "Identificar funciones esenciales y sus dependencias digitales y físicas."],
      ["Assess cyber scenarios together with safety and service consequences.", "Evaluar escenarios cibernéticos junto con consecuencias de seguridad y servicio."],
      ["Layer prevention, detection, manual fallback and restoration capability.", "Combinar prevención, detección, operación manual y capacidad de restauración."],
      ["Coordinate operators, authorities and suppliers before a crisis.", "Coordinar operadores, autoridades y proveedores antes de una crisis."]
    ]
  ),
  "essential-sectors": h(
    "Essential sectors deliver different outcomes but depend on common digital capabilities. A hospital relies on clinical systems, identity, electricity, communications and suppliers; a transport operator relies on signalling, scheduling, positioning and operational control; financial services rely on transaction integrity and market connectivity. Sector analysis maps these functions and identifies where cyber failure becomes a public-service, safety or economic problem.\n\nControls are adapted to the operating reality. A confidentiality-first approach suitable for one dataset may be wrong for an emergency service that must remain available. Sector regulations, threat intelligence, exercises and peer collaboration establish minimum expectations while allowing operators to manage their specific technology and risk.",
    "Los sectores esenciales prestan resultados distintos, pero dependen de capacidades digitales comunes. Un hospital necesita sistemas clínicos, identidad, electricidad, comunicaciones y proveedores; un operador de transporte depende de señalización, horarios, posicionamiento y control; los servicios financieros necesitan integridad de transacciones y conectividad de mercado. El análisis sectorial representa estas funciones y localiza dónde un fallo cibernético se convierte en un problema de servicio público, seguridad o economía.\n\nLos controles se adaptan a la realidad operativa. Un enfoque centrado en confidencialidad puede ser inadecuado para un servicio de emergencias que debe seguir disponible. Regulación sectorial, inteligencia, simulacros y colaboración entre iguales establecen expectativas mínimas sin ignorar la tecnología y el riesgo propios de cada operador.",
    [
      ["Define the essential outcome the sector must continue to deliver.", "Definir el resultado esencial que el sector debe seguir prestando."],
      ["Map technology, workforce, supplier and utility dependencies.", "Representar dependencias tecnológicas, humanas, de proveedores y suministros."],
      ["Set control priorities according to safety, availability and integrity needs.", "Priorizar controles según necesidades de seguridad, disponibilidad e integridad."],
      ["Use sector exercises and shared intelligence to test systemic readiness.", "Usar simulacros sectoriales e inteligencia compartida para probar la preparación sistémica."]
    ]
  ),
  "cascading-failures": h(
    "A cascading failure begins when disruption in one component removes a service that other systems assumed would be available. A telecommunications outage may prevent remote control, a power loss may stop network equipment, a time-source failure may corrupt transactions and a cloud identity outage may block many unrelated applications. Feedback loops can magnify the effect as automated recovery actions increase load on already stressed dependencies.\n\nAnalysis uses dependency maps and scenario simulation to follow the chain beyond the first failed asset. Teams identify concentration, shared suppliers, single regions and recovery plans that depend on the same unavailable service. Resilience comes from diversity, graceful degradation, local autonomy and recovery sequences that have been tested under combined failures.",
    "Un fallo en cascada comienza cuando la interrupción de un componente elimina un servicio que otros sistemas daban por disponible. Una caída de telecomunicaciones puede impedir el control remoto, la pérdida eléctrica detener equipos de red, un fallo de sincronización corromper transacciones y una caída del proveedor de identidad bloquear aplicaciones no relacionadas. Los bucles de realimentación pueden amplificar el efecto si la recuperación automática aumenta la carga sobre dependencias ya saturadas.\n\nEl análisis utiliza mapas de dependencias y simulación de escenarios para seguir la cadena más allá del primer activo fallido. Se buscan concentraciones, proveedores compartidos, regiones únicas y planes de recuperación que dependen del mismo servicio indisponible. La resiliencia se logra con diversidad, degradación controlada, autonomía local y secuencias de recuperación probadas ante fallos combinados.",
    [
      ["Trace upstream and downstream dependencies for each critical function.", "Trazar dependencias anteriores y posteriores de cada función crítica."],
      ["Model combined failures, capacity limits and automated feedback loops.", "Modelar fallos combinados, límites de capacidad y bucles automáticos."],
      ["Remove hidden concentration and shared single points of failure.", "Eliminar concentraciones ocultas y puntos únicos de fallo compartidos."],
      ["Test degraded operation and recovery in the correct dependency order.", "Probar operación degradada y recuperación en el orden correcto de dependencias."]
    ]
  ),
  "critical-resilience": h(
    "Critical resilience designs a service to absorb disruption, continue at an acceptable minimum level and recover without creating new hazards. Operators define the maximum tolerable outage and minimum viable service, then engineer redundancy, alternate communications, manual procedures and protected recovery resources. Monitoring identifies when the service is approaching unsafe limits and triggers escalation or controlled degradation.\n\nRecovery plans specify dependencies, priorities and authoritative decision makers. Exercises include cyber compromise, loss of staff, supplier outage and physical damage rather than testing backups in isolation. Lessons are converted into engineering changes, inventories, contracts and training so that resilience becomes an operational capability rather than a document.",
    "La resiliencia crítica diseña el servicio para absorber una interrupción, continuar a un nivel mínimo aceptable y recuperarse sin crear nuevos peligros. Los operadores definen la interrupción máxima tolerable y el servicio mínimo viable, y después diseñan redundancia, comunicaciones alternativas, procedimientos manuales y recursos de recuperación protegidos. La monitorización detecta cuándo el servicio se acerca a límites inseguros y activa escalado o degradación controlada.\n\nLos planes de recuperación especifican dependencias, prioridades y responsables con autoridad. Los simulacros combinan compromiso cibernético, falta de personal, caída de proveedores y daño físico en vez de probar copias de forma aislada. Las lecciones se convierten en cambios de ingeniería, inventarios, contratos y formación para que la resiliencia sea una capacidad operativa y no un documento.",
    [
      ["Define minimum viable service and maximum tolerable disruption.", "Definir servicio mínimo viable e interrupción máxima tolerable."],
      ["Design independent redundancy, fallback and protected recovery resources.", "Diseñar redundancia independiente, alternativas y recursos de recuperación protegidos."],
      ["Monitor operating limits and trigger controlled degradation early.", "Monitorizar límites operativos y activar pronto una degradación controlada."],
      ["Exercise multi-cause crises and turn lessons into engineering changes.", "Ensayar crisis con varias causas y convertir lecciones en cambios de ingeniería."]
    ]
  ),
  "ot-ics": h(
    "Operational technology controls physical processes through sensors, programmable controllers, supervisory systems and actuators. Field devices measure temperature, pressure, speed or position; controllers execute deterministic logic; supervisory systems display process state and send setpoints; safety systems may independently move the process to a safe condition. Availability and predictable timing often matter more than rapid software change.\n\nCybersecurity must therefore understand process physics. A malicious command, delayed packet or false sensor value can affect equipment and people even when no data is stolen. Controls emphasise segmentation, authenticated engineering access, change control, passive monitoring and coordination with safety procedures. Testing that could interrupt a live process is performed in laboratories or planned outages.",
    "La tecnología operacional controla procesos físicos mediante sensores, controladores programables, sistemas de supervisión y actuadores. Los dispositivos de campo miden temperatura, presión, velocidad o posición; los controladores ejecutan lógica determinista; los sistemas de supervisión muestran el estado y envían consignas; y los sistemas de seguridad pueden llevar el proceso a una condición segura de forma independiente. La disponibilidad y el tiempo predecible suelen importar más que cambiar software con rapidez.\n\nLa ciberseguridad debe comprender la física del proceso. Un comando malicioso, un paquete retrasado o un valor de sensor falso pueden afectar a equipos y personas aunque no se robe información. Los controles priorizan segmentación, acceso de ingeniería autenticado, gestión de cambios, monitorización pasiva y coordinación con procedimientos de seguridad. Las pruebas que podrían interrumpir producción se realizan en laboratorios o paradas planificadas.",
    [
      ["Map the process from sensors and controllers to supervisory and safety systems.", "Representar el proceso desde sensores y controladores hasta supervisión y seguridad."],
      ["Identify commands and data whose manipulation could create physical consequences.", "Identificar comandos y datos cuya manipulación tendría consecuencias físicas."],
      ["Restrict engineering paths and monitor protocols without disrupting operations.", "Restringir rutas de ingeniería y monitorizar protocolos sin interrumpir la operación."],
      ["Coordinate cyber response with operators, maintenance and safety teams.", "Coordinar respuesta cibernética con operación, mantenimiento y seguridad física."]
    ]
  ),
  "ot-architecture": h(
    "A secure OT architecture separates enterprise, supervisory, control and safety functions into zones and conduits. An industrial demilitarised zone brokers data exchange so that business systems do not connect directly to controllers. Firewalls allow only required industrial protocols and directions, and remote administration passes through monitored jump hosts. Safety systems remain sufficiently independent that compromise of normal control does not remove the final protective layer.\n\nThe design also accounts for shared services such as time, identity, patch repositories and historians. A diagram is validated against actual traffic and physical connections, because undocumented modems, dual-homed engineering laptops or vendor appliances can bypass the intended boundary. Changes are reviewed for both cyber and process-safety impact.",
    "Una arquitectura OT segura separa funciones empresariales, de supervisión, control y seguridad en zonas y conductos. Una zona desmilitarizada industrial intermedia el intercambio para que los sistemas corporativos no conecten directamente con controladores. Los firewalls permiten solo protocolos y direcciones industriales necesarios, y la administración remota pasa por bastiones monitorizados. Los sistemas de seguridad mantienen suficiente independencia para que comprometer el control normal no elimine la última protección.\n\nEl diseño también considera servicios compartidos como hora, identidad, repositorios de parches e historiadores. El diagrama se valida frente al tráfico y las conexiones físicas reales, porque módems no documentados, portátiles de ingeniería con dos redes o equipos de proveedores pueden saltarse el límite previsto. Cada cambio se revisa por impacto cibernético y de seguridad del proceso.",
    [
      ["Group assets into zones according to function and consequence.", "Agrupar activos en zonas según función y consecuencia."],
      ["Define tightly controlled conduits for required industrial flows.", "Definir conductos muy controlados para los flujos industriales necesarios."],
      ["Broker enterprise and remote access through an industrial DMZ.", "Intermediar el acceso corporativo y remoto mediante una DMZ industrial."],
      ["Preserve independence of safety and recovery mechanisms.", "Conservar la independencia de mecanismos de seguridad y recuperación."]
    ]
  ),
  "ot-monitoring-assets": h(
    "OT asset inventory is built by combining engineering drawings, controller projects, maintenance records, switch tables and passive observation of industrial protocols. Passive sensors identify communicating devices, roles, firmware, commands and relationships without actively probing fragile equipment. The resulting inventory links each asset to process function, location, owner, vendor and operational criticality.\n\nMonitoring then establishes normal patterns such as which engineering station programs which controller and when. Alerts focus on meaningful deviations: a new device, unexpected firmware download, write command from the wrong zone or communication outside a maintenance window. Analysts confirm observations with operators because unusual traffic may represent a legitimate process event rather than an attack.",
    "El inventario OT se construye combinando planos de ingeniería, proyectos de controladores, registros de mantenimiento, tablas de switches y observación pasiva de protocolos industriales. Los sensores pasivos identifican dispositivos, funciones, firmware, comandos y relaciones sin sondear activamente equipos frágiles. El inventario resultante vincula cada activo con función de proceso, ubicación, responsable, fabricante y criticidad operativa.\n\nLa monitorización establece después patrones normales, como qué estación de ingeniería programa cada controlador y en qué momentos. Las alertas se centran en desviaciones significativas: un dispositivo nuevo, una descarga de firmware inesperada, una orden de escritura desde la zona equivocada o comunicación fuera de mantenimiento. Los analistas confirman las observaciones con operadores porque un tráfico inusual puede ser un evento legítimo del proceso.",
    [
      ["Collect authoritative engineering and maintenance records.", "Recopilar registros de ingeniería y mantenimiento fiables."],
      ["Observe industrial traffic passively to discover assets and relationships.", "Observar tráfico industrial de forma pasiva para descubrir activos y relaciones."],
      ["Link each device to process function, owner, location and criticality.", "Vincular cada dispositivo con función, responsable, ubicación y criticidad."],
      ["Detect deviations and validate them with operational context.", "Detectar desviaciones y validarlas con contexto operativo."]
    ]
  ),
  "ot-remote-vendor-access": h(
    "OT remote access is opened for a specific maintenance task rather than left permanently available. The vendor authenticates with an individual, strongly protected identity, connects through a controlled gateway and receives time-limited access to a named asset. A jump host records the session and prevents direct connectivity from the vendor device to the control network. File transfer is scanned and separately approved.\n\nOperations staff authorise the window and can observe or terminate the work. Shared vendor accounts, unmanaged modems and always-on tunnels remove accountability and create hidden paths. After the task, credentials and routes are disabled, changes are reviewed and any transferred tools are removed or retained under control.",
    "El acceso remoto OT se abre para una tarea de mantenimiento concreta en vez de quedar disponible de forma permanente. El proveedor se autentica con una identidad individual y reforzada, conecta mediante una pasarela controlada y recibe acceso temporal a un activo identificado. Un bastión registra la sesión e impide conectividad directa desde el dispositivo del proveedor hasta la red de control. La transferencia de ficheros se analiza y aprueba por separado.\n\nEl personal de operaciones autoriza la ventana y puede observar o terminar el trabajo. Las cuentas compartidas, módems sin gestionar y túneles siempre activos eliminan trazabilidad y crean rutas ocultas. Al terminar, se deshabilitan credenciales y rutas, se revisan los cambios y se retiran o controlan las herramientas transferidas.",
    [
      ["Approve a defined maintenance purpose, asset and time window.", "Aprobar una finalidad, un activo y una ventana de mantenimiento concretos."],
      ["Authenticate the named technician and assess the connecting endpoint.", "Autenticar al técnico identificado y evaluar su equipo."],
      ["Broker and record the session through a restricted jump path.", "Intermediar y registrar la sesión mediante una ruta restringida."],
      ["Close access, review changes and preserve the audit record afterwards.", "Cerrar el acceso, revisar cambios y conservar el registro al finalizar."]
    ]
  ),
  "ot-incident-recovery": h(
    "OT incident response begins with process safety and service state. Operators determine whether the process remains stable, whether control views can be trusted and whether a cyber containment action could create a hazardous transition. Network isolation, controller shutdown or credential revocation is coordinated with engineering and safety authority rather than applied automatically from an IT playbook.\n\nEvidence is collected without overwriting fragile devices, while known-good logic, configurations and firmware are compared with the installed state. Recovery follows an engineered order: establish safe manual or local control, restore supporting infrastructure, validate controllers and safety interlocks, then reconnect supervision and business interfaces. Production resumes only after process behaviour and cyber integrity have both been checked.",
    "La respuesta a incidentes OT comienza por la seguridad y el estado del proceso. Los operadores determinan si sigue estable, si puede confiarse en las pantallas de control y si una acción de contención cibernética provocaría una transición peligrosa. El aislamiento de red, apagado de controladores o revocación de credenciales se coordina con ingeniería y autoridad de seguridad en vez de aplicarse automáticamente desde un manual de TI.\n\nLas evidencias se recogen sin sobrescribir dispositivos frágiles, y se comparan lógica, configuraciones y firmware conocidos con el estado instalado. La recuperación sigue un orden diseñado: establecer control manual o local seguro, restaurar infraestructura de apoyo, validar controladores e interbloqueos y después reconectar supervisión e interfaces empresariales. La producción vuelve solo tras comprobar comportamiento físico e integridad cibernética.",
    [
      ["Stabilise the physical process and establish trustworthy operational awareness.", "Estabilizar el proceso físico y obtener una visión operativa fiable."],
      ["Select containment actions with engineering and safety approval.", "Elegir acciones de contención con aprobación de ingeniería y seguridad."],
      ["Preserve evidence and compare control logic with known-good versions.", "Conservar evidencias y comparar la lógica de control con versiones fiables."],
      ["Restore in dependency order and validate cyber and physical behaviour.", "Restaurar según dependencias y validar comportamiento cibernético y físico."]
    ]
  ),
  "incident-response": h(
    "Incident response turns uncertain technical signals into coordinated action. Preparation defines roles, contact routes, tools, evidence procedures and decision authority. Detection and analysis confirm whether an event is malicious, identify affected identities and assets, estimate scope and classify severity. Containment then limits attacker access while preserving essential service and evidence.\n\nEradication removes persistence, closes the entry route and resets compromised trust. Recovery restores systems in a controlled order, monitors for recurrence and confirms that business processes work correctly. The final review reconstructs the timeline, identifies control and decision failures and assigns improvements. Phases may overlap: new evidence during recovery can force renewed containment or broader investigation.",
    "La respuesta a incidentes convierte señales técnicas inciertas en una actuación coordinada. La preparación define funciones, contactos, herramientas, procedimientos de evidencia y autoridad para decidir. La detección y el análisis confirman si el evento es malicioso, identifican identidades y activos afectados, estiman el alcance y clasifican la gravedad. La contención limita después el acceso del atacante sin destruir pruebas ni interrumpir innecesariamente el servicio esencial.\n\nLa erradicación elimina persistencia, cierra la vía de entrada y restablece la confianza comprometida. La recuperación restaura sistemas en un orden controlado, vigila la reaparición y confirma que los procesos funcionan. La revisión final reconstruye la cronología, identifica fallos de control y decisión y asigna mejoras. Las fases pueden solaparse: nuevas evidencias durante la recuperación pueden exigir otra contención.",
    [
      ["Prepare authority, playbooks, communications and evidence capability.", "Preparar autoridad, procedimientos, comunicaciones y capacidad de evidencias."],
      ["Confirm the incident, scope affected assets and assess business impact.", "Confirmar el incidente, delimitar activos afectados y valorar el impacto."],
      ["Contain and eradicate attacker access without losing critical evidence.", "Contener y erradicar el acceso del atacante sin perder evidencias críticas."],
      ["Recover under observation and convert lessons into owned improvements.", "Recuperar bajo observación y convertir lecciones en mejoras con responsable."]
    ]
  ),
  "containment-recovery": h(
    "Containment chooses how to stop further harm while keeping enough visibility to understand the incident. Short-term actions may isolate a host, block a token, disable an account or restrict a network route. Longer-term containment creates a clean administrative environment, segments affected areas and replaces compromised credentials. Each action is assessed for operational side effects and the risk of warning the attacker too early.\n\nRecovery does not simply switch systems back on. Teams rebuild from trusted media, restore verified data, rotate keys, close the exploited path and reconnect services in dependency order. Enhanced monitoring watches for persistence and validates normal business transactions. A recovery point is accepted only when both technical integrity and service outcome are demonstrated.",
    "La contención decide cómo detener el daño sin perder la visibilidad necesaria para comprender el incidente. Entre las acciones inmediatas están aislar un equipo, bloquear un token, deshabilitar una cuenta o restringir una ruta de red. La contención sostenida crea un entorno administrativo limpio, segmenta las zonas afectadas y sustituye credenciales comprometidas. Cada medida se valora por sus efectos operativos y por el riesgo de alertar al atacante demasiado pronto.\n\nRecuperar no consiste en volver a encender sistemas. Se reconstruye desde medios fiables, se restauran datos verificados, se rotan claves, se cierra la vía explotada y se reconectan servicios según sus dependencias. Una monitorización reforzada busca persistencia y valida transacciones normales. La recuperación solo se acepta cuando se demuestran integridad técnica y resultado del servicio.",
    [
      ["Select reversible containment that stops the most urgent harm.", "Elegir una contención reversible que detenga el daño más urgente."],
      ["Build a clean control plane and replace compromised trust material.", "Crear un plano de control limpio y sustituir el material de confianza comprometido."],
      ["Restore verified systems and data in dependency order.", "Restaurar sistemas y datos verificados según el orden de dependencias."],
      ["Monitor closely and validate real business operation before closure.", "Monitorizar estrechamente y validar la operación real antes de cerrar."]
    ]
  ),
  "incident-communication": h(
    "Incident communication provides different audiences with accurate information at the pace they need. The response team maintains a confirmed fact set, a decision log and a regular reporting rhythm. Executives receive impact, choices and resource needs; technical teams receive indicators and actions; employees receive instructions; customers, regulators and partners receive information required by law, contract and trust.\n\nMessages distinguish confirmed facts from hypotheses and avoid promising dates that the recovery team cannot support. Legal, privacy, security and communications specialists coordinate wording without blocking urgent operational information. A single source of truth reduces contradiction, while updates explain what changed since the previous notice and when the next one will arrive.",
    "La comunicación de incidentes proporciona a cada audiencia información precisa con la frecuencia que necesita. El equipo mantiene un conjunto de hechos confirmados, un registro de decisiones y un ritmo fijo de informes. La dirección recibe impacto, opciones y necesidades; los equipos técnicos, indicadores y acciones; los empleados, instrucciones; y clientes, reguladores y colaboradores, la información exigida por ley, contrato y confianza.\n\nLos mensajes distinguen hechos confirmados de hipótesis y evitan prometer fechas que recuperación no puede sostener. Especialistas legales, de privacidad, seguridad y comunicación coordinan el contenido sin bloquear información operativa urgente. Una fuente única reduce contradicciones, y cada actualización explica qué ha cambiado y cuándo llegará la siguiente.",
    [
      ["Maintain confirmed facts, open questions and a decision record.", "Mantener hechos confirmados, preguntas abiertas y registro de decisiones."],
      ["Tailor content and frequency to each operational and external audience.", "Adaptar contenido y frecuencia a cada audiencia operativa y externa."],
      ["Coordinate legal duties without obscuring urgent instructions.", "Coordinar obligaciones legales sin ocultar instrucciones urgentes."],
      ["State uncertainty, changes and the time of the next update clearly.", "Expresar con claridad incertidumbre, cambios y hora de la siguiente actualización."]
    ]
  ),
  "digital-forensics": h(
    "Digital forensics acquires, preserves, analyses and explains digital evidence in a repeatable manner. Investigators first define the question and legal authority, then collect volatile data, disks, cloud records or device artefacts using methods that minimise alteration. Hashes, timestamps, custody records and tool versions document the integrity and handling of every item.\n\nAnalysis reconstructs actions from independent sources rather than trusting one log. Deleted files, process artefacts, browser history, memory, registry data and network records may reveal different parts of the event. Findings distinguish observation from interpretation and state limitations, because missing logs, clock drift or encryption can prevent certainty. The final report must be understandable to decision makers as well as technically defensible.",
    "La informática forense adquiere, conserva, analiza y explica evidencias digitales de forma repetible. Primero se define la pregunta y la autoridad legal; después se recogen datos volátiles, discos, registros de nube o artefactos de dispositivos con métodos que minimizan alteraciones. Hashes, marcas de tiempo, cadena de custodia y versiones de herramientas documentan integridad y manejo de cada elemento.\n\nEl análisis reconstruye acciones mediante fuentes independientes en vez de confiar en un único log. Ficheros borrados, procesos, historial del navegador, memoria, registro y datos de red pueden mostrar partes distintas. Las conclusiones separan observación e interpretación y declaran limitaciones, porque la ausencia de registros, relojes desviados o cifrado pueden impedir certeza. El informe final debe ser comprensible y técnicamente defendible.",
    [
      ["Define the investigative question, authority and evidence scope.", "Definir la pregunta, autoridad y alcance de evidencias."],
      ["Acquire volatile and persistent data while recording integrity and custody.", "Adquirir datos volátiles y persistentes registrando integridad y custodia."],
      ["Correlate independent artefacts into a tested timeline.", "Correlacionar artefactos independientes en una cronología contrastada."],
      ["Report facts, inferences, confidence and limitations separately.", "Informar por separado de hechos, inferencias, confianza y limitaciones."]
    ]
  ),
  "forensic-sources": h(
    "A forensic timeline combines events from endpoints, identity systems, applications, cloud control planes, network devices and external services. Each source records a different perspective and may use a different clock, format or retention period. Investigators normalise time zones, account for drift, preserve original values and connect records through identifiers such as user, host, process, session, IP address or request ID.\n\nThe timeline is iteratively tested. A login may be legitimate unless followed by a new token, unusual process and outbound transfer; a missing event may indicate log loss rather than absence of activity. Investigators therefore look for corroboration and explain gaps. Source quality, collection delay and parsing errors are recorded alongside the conclusions.",
    "Una línea temporal forense combina eventos de equipos, identidad, aplicaciones, planos de control de nube, dispositivos de red y servicios externos. Cada fuente ofrece una perspectiva distinta y puede usar otro reloj, formato o periodo de conservación. Se normalizan zonas horarias, se considera la deriva, se conservan valores originales y se conectan registros mediante usuario, equipo, proceso, sesión, IP o identificador de solicitud.\n\nLa cronología se contrasta de forma iterativa. Un inicio de sesión puede ser legítimo salvo que le sigan un token nuevo, un proceso anómalo y una transferencia; un evento ausente puede indicar pérdida de logs, no ausencia de actividad. Por eso se busca corroboración y se explican vacíos. La calidad de fuente, retraso de recogida y errores de análisis se registran junto a las conclusiones.",
    [
      ["Collect complementary sources before retention windows expire.", "Recoger fuentes complementarias antes de que expire su conservación."],
      ["Normalise timestamps while preserving original time and provenance.", "Normalizar tiempos conservando valor original y procedencia."],
      ["Link events through stable identifiers and causal relationships.", "Relacionar eventos mediante identificadores estables y causalidad."],
      ["Test the timeline against alternative explanations and known gaps.", "Contrastar la cronología con explicaciones alternativas y vacíos conocidos."]
    ]
  ),
  "security-operations": h(
    "A security operations centre receives telemetry, turns detections into cases and coordinates investigation and response. Collection pipelines normalise identity, endpoint, network, cloud and application events. Detection rules and analytics create alerts; triage determines whether they are benign, suspicious or incidents; case management records evidence, actions and ownership. Escalation connects analysts with system owners, incident responders and business decision makers.\n\nThe SOC also improves its own system. It measures coverage, alert quality, investigation time, recurrence and response outcome, then tunes noisy rules and closes blind spots. Automation enriches and performs safe repetitive actions, but analysts retain judgement for ambiguous context and high-impact containment.",
    "Un centro de operaciones recibe telemetría, convierte detecciones en casos y coordina investigación y respuesta. Las canalizaciones normalizan eventos de identidad, equipos, red, nube y aplicaciones. Reglas y análisis generan alertas; el triaje decide si son benignas, sospechosas o incidentes; y la gestión de casos registra evidencias, acciones y responsable. El escalado conecta analistas con propietarios de sistemas, respuesta a incidentes y dirección.\n\nEl SOC también mejora su propio sistema. Mide cobertura, calidad de alertas, tiempo de investigación, recurrencia y resultado, ajusta reglas ruidosas y cierra puntos ciegos. La automatización enriquece y ejecuta acciones repetitivas seguras, pero el juicio humano sigue siendo necesario ante contexto ambiguo y contenciones de alto impacto.",
    [
      ["Collect reliable telemetry with known ownership and retention.", "Recoger telemetría fiable con responsable y conservación conocidos."],
      ["Triage alerts using context, evidence and defined severity criteria.", "Priorizar alertas con contexto, evidencias y criterios de gravedad."],
      ["Investigate and coordinate proportionate response through managed cases.", "Investigar y coordinar una respuesta proporcionada mediante casos gestionados."],
      ["Measure outcomes and improve detection coverage and analyst workflow.", "Medir resultados y mejorar cobertura de detección y flujo de analistas."]
    ]
  ),
  "detection-engineering": h(
    "Detection engineering starts with a behaviour or threat hypothesis, not a product query. Engineers describe what the attacker must do, identify data sources that would observe it and define the fields and quality required. They create logic, test it against representative benign and malicious data, document expected false positives and map the detection to an investigation procedure.\n\nAfter deployment, performance is monitored through alert volume, confirmed cases, missed simulations and changes in telemetry. Rules are versioned, peer-reviewed and tested like software. When an attacker or system changes, the detection is refined or retired. Coverage is measured across attack techniques and critical assets, not by counting the total number of rules.",
    "La ingeniería de detección parte de un comportamiento o hipótesis de amenaza, no de una consulta de producto. Se describe qué debe hacer el atacante, qué fuentes podrían observarlo y qué campos y calidad son necesarios. Se crea la lógica, se prueba con datos benignos y maliciosos representativos, se documentan falsos positivos esperados y se vincula a un procedimiento de investigación.\n\nTras desplegarla, se monitorizan volumen, casos confirmados, simulaciones no detectadas y cambios de telemetría. Las reglas se versionan, revisan y prueban como software. Cuando cambia el atacante o el sistema, la detección se ajusta o retira. La cobertura se mide sobre técnicas y activos críticos, no por el número total de reglas.",
    [
      ["Define the adversary behaviour and observable evidence.", "Definir el comportamiento adversario y la evidencia observable."],
      ["Verify that required telemetry is complete, timely and correctly parsed.", "Verificar que la telemetría necesaria sea completa, puntual y esté bien interpretada."],
      ["Test logic against realistic positive and negative examples.", "Probar la lógica con ejemplos positivos y negativos realistas."],
      ["Deploy with an investigation guide, metrics and version control.", "Desplegar con guía de investigación, métricas y control de versiones."]
    ]
  ),
  "threat-hunting-intelligence": h(
    "Threat intelligence collects and assesses information about adversaries, infrastructure, vulnerabilities and campaigns, then converts it into decisions. Strategic intelligence supports risk and investment; operational intelligence explains campaigns; tactical intelligence describes techniques; and technical indicators support short-lived searches or blocking. Source reliability, information age and confidence are recorded so that consumers do not treat every claim equally.\n\nThreat hunting uses a hypothesis to search existing telemetry for activity that did not trigger an alert. Hunters choose a behaviour, identify the necessary data, query across systems, validate anomalies and scope confirmed activity. The result may be an incident, a new detection, a logging improvement or evidence that the hypothesis was unsupported.",
    "La inteligencia de amenazas recopila y evalúa información sobre adversarios, infraestructura, vulnerabilidades y campañas y la convierte en decisiones. La inteligencia estratégica apoya riesgo e inversión; la operacional explica campañas; la táctica describe técnicas; y los indicadores técnicos permiten búsquedas o bloqueos de corta duración. Se registra fiabilidad de fuente, antigüedad y confianza para no tratar todas las afirmaciones por igual.\n\nLa búsqueda de amenazas usa una hipótesis para localizar en la telemetría actividad que no generó alerta. Se elige un comportamiento, se identifican los datos necesarios, se consulta entre sistemas, se validan anomalías y se delimita actividad confirmada. El resultado puede ser un incidente, una detección nueva, una mejora de los registros o la conclusión de que la hipótesis no estaba respaldada.",
    [
      ["Assess sources, confidence, relevance and expiry of threat information.", "Evaluar fuentes, confianza, relevancia y caducidad de la información."],
      ["Turn intelligence into a testable behaviour-focused hunting hypothesis.", "Convertir inteligencia en una hipótesis de búsqueda comprobable y basada en comportamiento."],
      ["Search across telemetry and validate anomalies with system context.", "Buscar en la telemetría y validar anomalías con contexto del sistema."],
      ["Feed confirmed learning into incidents, detections and control priorities.", "Incorporar el aprendizaje confirmado a incidentes, detecciones y prioridades de control."]
    ]
  ),
  "governance-risk-compliance": h(
    "Governance establishes who can make security decisions, what outcomes are expected and how performance is overseen. Policies set direction, standards define mandatory requirements, procedures explain execution and controls produce evidence. Risk management connects technical conditions to organisational objectives, while compliance compares actual practice with legal, regulatory, contractual and internal obligations.\n\nA functioning GRC system does not treat all three as paperwork. Risks and control failures are assigned to accountable owners, exceptions have expiry dates and management receives information that supports decisions. Assurance activities such as testing, audit and review check whether controls operate effectively, not merely whether a policy exists.",
    "El gobierno establece quién puede tomar decisiones de seguridad, qué resultados se esperan y cómo se supervisa el desempeño. Las políticas marcan dirección, los estándares definen requisitos obligatorios, los procedimientos explican la ejecución y los controles generan evidencias. La gestión de riesgos conecta condiciones técnicas con objetivos de la organización, mientras el cumplimiento compara la práctica real con obligaciones legales, regulatorias, contractuales e internas.\n\nUn sistema GRC útil no convierte las tres materias en papeleo. Los riesgos y fallos de control se asignan a responsables, las excepciones caducan y la dirección recibe información para decidir. Pruebas, auditorías y revisiones comprueban si los controles funcionan, no solo si existe una política.",
    [
      ["Define decision rights, accountability and security objectives.", "Definir autoridad de decisión, responsabilidad y objetivos de seguridad."],
      ["Translate obligations and risk decisions into policies and controls.", "Traducir obligaciones y decisiones de riesgo a políticas y controles."],
      ["Collect evidence and test control design and operating effectiveness.", "Recoger evidencias y probar diseño y eficacia operativa de controles."],
      ["Report exceptions, trends and residual risk to the right authority.", "Informar de excepciones, tendencias y riesgo residual a la autoridad adecuada."]
    ]
  ),
  "risk-treatment": h(
    "Risk treatment follows assessment with a deliberate decision. Avoidance removes the activity or design that creates the risk; reduction changes likelihood or impact through controls; transfer shares financial or operational consequences through insurance or contract; and acceptance records that the remaining exposure is within authority and appetite. Several treatments can be combined, but none removes accountability from the organisation.\n\nA treatment plan states the target risk, actions, cost, owner and completion date. After implementation, evidence is gathered to estimate residual risk and identify side effects or dependencies. Acceptance is time-limited and reviewed when threats, assets, controls or business importance change.",
    "El tratamiento del riesgo continúa la evaluación con una decisión deliberada. Evitar elimina la actividad o diseño que origina el riesgo; reducir modifica probabilidad o impacto mediante controles; transferir comparte consecuencias económicas u operativas mediante seguro o contrato; y aceptar registra que la exposición restante está dentro de la autoridad y apetito. Pueden combinarse tratamientos, pero ninguno elimina la responsabilidad de la organización.\n\nEl plan indica riesgo objetivo, acciones, coste, responsable y fecha. Tras implantarlo se recogen evidencias para estimar el riesgo residual e identificar efectos secundarios o dependencias. La aceptación tiene duración limitada y se revisa cuando cambian amenazas, activos, controles o importancia del negocio.",
    [
      ["Compare the assessed risk with appetite and decision authority.", "Comparar el riesgo evaluado con el apetito y la autoridad de decisión."],
      ["Choose avoidance, reduction, transfer, acceptance or a combination.", "Elegir evitar, reducir, transferir, aceptar o combinar opciones."],
      ["Define measurable actions, owner, resources and target completion.", "Definir acciones medibles, responsable, recursos y fecha objetivo."],
      ["Verify residual risk and review the decision when conditions change.", "Verificar el riesgo residual y revisar la decisión cuando cambien las condiciones."]
    ]
  ),
  "frameworks-standards": h(
    "A security framework organises outcomes and activities so that an organisation can assess and improve its programme. A standard may define auditable requirements, while guidance explains possible implementation. Teams select a framework according to purpose, scope and obligations, map its language to existing processes and identify gaps using evidence. They then prioritise improvements according to risk instead of mechanically implementing every possible control.\n\nCrosswalks help relate different frameworks, but similar headings do not always mean equivalent assurance. Certification, where available, confirms conformity within a defined scope and time; it does not prove that every system is secure. The framework remains useful only when updated to reflect actual architecture, responsibilities and operating results.",
    "Un marco de seguridad organiza resultados y actividades para evaluar y mejorar un programa. Una norma puede definir requisitos auditables, mientras una guía explica formas de implantación. Los equipos eligen según finalidad, alcance y obligaciones, relacionan su lenguaje con procesos existentes e identifican carencias mediante evidencias. Después priorizan mejoras por riesgo en vez de aplicar mecánicamente todos los controles posibles.\n\nLas equivalencias ayudan a relacionar marcos, pero encabezados parecidos no garantizan la misma seguridad. Una certificación, cuando existe, confirma conformidad dentro de un alcance y momento definidos; no demuestra que todos los sistemas sean seguros. El marco solo sigue siendo útil si refleja arquitectura, responsabilidades y resultados operativos reales.",
    [
      ["Choose a framework whose purpose and scope match the organisation.", "Elegir un marco cuya finalidad y alcance encajen con la organización."],
      ["Map requirements to real processes, assets, controls and evidence.", "Relacionar requisitos con procesos, activos, controles y evidencias reales."],
      ["Prioritise gaps by risk and dependency rather than checklist order.", "Priorizar carencias por riesgo y dependencia, no por orden de lista."],
      ["Reassess maturity and effectiveness as the environment changes.", "Reevaluar madurez y eficacia cuando cambie el entorno."]
    ]
  ),
  "third-party-risk": h(
    "Third-party risk management begins before purchase by defining what data, access, service and dependency a supplier will receive. Due diligence examines security capability, financial and operational resilience, subcontractors, incident history and relevant assurance evidence. Contract terms then set minimum controls, breach notification, audit rights, data handling, recovery expectations and exit support.\n\nRisk continues after onboarding. Access and integrations are inventoried, supplier posture and service performance are monitored, and material changes trigger reassessment. Concentration is also examined: several critical services may depend on the same cloud, software component or support company. At termination, accounts, tokens, data copies and physical assets are returned or verifiably destroyed.",
    "La gestión de terceros comienza antes de comprar, definiendo qué datos, acceso, servicio y dependencia recibirá el proveedor. La diligencia debida examina capacidad de seguridad, resiliencia económica y operativa, subcontratistas, historial de incidentes y evidencias de garantía. El contrato fija controles mínimos, notificación de brechas, derecho de auditoría, tratamiento de datos, recuperación y apoyo a la salida.\n\nEl riesgo continúa tras el alta. Se inventarían accesos e integraciones, se monitorizan postura y prestación, y los cambios relevantes provocan reevaluación. También se analiza concentración: varios servicios críticos pueden depender de la misma nube, componente o empresa de soporte. Al terminar, cuentas, tokens, copias de datos y activos físicos se devuelven o destruyen de forma verificable.",
    [
      ["Define the service, data, privileges and critical dependencies involved.", "Definir servicio, datos, privilegios y dependencias críticas implicados."],
      ["Assess the supplier and important subcontractors before approval.", "Evaluar al proveedor y subcontratistas importantes antes de aprobar."],
      ["Set enforceable security, notification, resilience and exit obligations.", "Fijar obligaciones exigibles de seguridad, notificación, resiliencia y salida."],
      ["Monitor changes and revoke all inherited trust at termination.", "Monitorizar cambios y revocar toda confianza heredada al finalizar."]
    ]
  ),
  "privacy-fundamentals": h(
    "Privacy management starts by identifying personal data, the people concerned, the purpose of processing and the lawful basis or authority. Principles such as purpose limitation, data minimisation, accuracy, storage limitation and transparency shape the design. Individuals are informed about use and, where applicable, can exercise rights such as access, correction, deletion or objection.\n\nThe organisation maps sharing, international transfers, processors and retention. Security protects confidentiality and integrity, but privacy also asks whether data should be collected or used at all, whether profiling is fair and whether people can understand the consequences. High-risk processing receives a formal impact assessment before deployment.",
    "La gestión de privacidad comienza identificando datos personales, personas afectadas, finalidad del tratamiento y base jurídica o autoridad. Principios como limitación de finalidad, minimización, exactitud, conservación limitada y transparencia orientan el diseño. Se informa a las personas y, cuando corresponde, pueden ejercer derechos de acceso, rectificación, supresión u oposición.\n\nLa organización representa cesiones, transferencias internacionales, encargados y plazos de conservación. La seguridad protege confidencialidad e integridad, pero la privacidad también pregunta si el dato debería recogerse o utilizarse, si el perfilado es justo y si las personas comprenden las consecuencias. Los tratamientos de alto riesgo se someten a una evaluación de impacto antes del despliegue.",
    [
      ["Record personal data, purpose, legal basis and affected people.", "Registrar datos personales, finalidad, base jurídica y personas afectadas."],
      ["Collect and retain only what is necessary for the stated purpose.", "Recoger y conservar solo lo necesario para la finalidad declarada."],
      ["Provide transparency and workable processes for individual rights.", "Ofrecer transparencia y procesos efectivos para derechos individuales."],
      ["Assess high-risk uses, sharing and transfers before they begin.", "Evaluar usos de alto riesgo, cesiones y transferencias antes de iniciarlos."]
    ]
  ),
  "privacy-engineering": h(
    "Privacy engineering converts privacy principles into technical and product decisions. Teams begin with data-flow mapping and identify where personal data enters, is inferred, combined, exposed and deleted. They then minimise fields, separate identities from content, use aggregation or pseudonymisation, limit defaults, shorten retention and provide controls that users can understand.\n\nPrivacy by default means the initial configuration reveals and shares no more than necessary without requiring expert action. Impact assessments test expected and unintended use, including discrimination, re-identification and function creep. Requirements become acceptance criteria, automated checks and production metrics so that privacy is maintained after launch rather than reviewed only in legal documentation.",
    "La ingeniería de privacidad convierte principios en decisiones técnicas y de producto. Se empieza representando flujos de datos e identificando dónde entran, se infieren, combinan, exponen y eliminan datos personales. Después se reducen campos, se separa identidad de contenido, se aplica agregación o seudonimización, se limitan valores iniciales, se acorta conservación y se ofrecen controles comprensibles.\n\nPrivacidad por defecto significa que la configuración inicial no revela ni comparte más de lo necesario sin exigir conocimientos expertos. Las evaluaciones prueban usos previstos y no previstos, incluida discriminación, reidentificación y ampliación de finalidad. Los requisitos se convierten en criterios de aceptación, comprobaciones automáticas y métricas de producción para mantener la privacidad tras el lanzamiento.",
    [
      ["Map personal-data flows, inferences and identity linkages.", "Representar flujos de datos personales, inferencias y vínculos de identidad."],
      ["Minimise collection, granularity, exposure and retention by design.", "Minimizar por diseño recogida, detalle, exposición y conservación."],
      ["Use protective defaults and controls understandable to real users.", "Usar valores protectores y controles comprensibles para usuarios reales."],
      ["Test re-identification, misuse and function-creep scenarios continuously.", "Probar continuamente reidentificación, abuso y ampliación de finalidad."]
    ]
  ),
  "cyber-resilience": h(
    "Cyber resilience assumes that some disruptions will bypass prevention and designs the organisation to continue, adapt and recover. Critical services are decomposed into people, technology, data, facilities and suppliers; tolerable downtime and minimum output are defined; and alternative ways of working are prepared. Detection and crisis management identify when normal controls are no longer enough and shift the organisation into a degraded but controlled mode.\n\nRecovery resources are isolated from the compromised environment and exercised under realistic conditions. After restoration, the organisation adapts architecture, contracts, staffing and procedures using evidence from incidents and exercises. Resilience is measured by service outcome and recovery quality, not simply by the number of redundant systems.",
    "La ciberresiliencia asume que algunas interrupciones superarán la prevención y diseña la organización para continuar, adaptarse y recuperarse. Los servicios críticos se descomponen en personas, tecnología, datos, instalaciones y proveedores; se definen tiempo tolerable y producción mínima; y se preparan formas alternativas de trabajo. La detección y la gestión de crisis reconocen cuándo los controles normales no bastan y trasladan la organización a un modo degradado pero controlado.\n\nLos recursos de recuperación se aíslan del entorno comprometido y se ensayan en condiciones realistas. Después se adaptan arquitectura, contratos, personal y procedimientos con evidencias de incidentes y ejercicios. La resiliencia se mide por el resultado del servicio y la calidad de recuperación, no por el número de sistemas redundantes.",
    [
      ["Define critical outcomes, tolerable disruption and minimum operating level.", "Definir resultados críticos, interrupción tolerable y nivel mínimo de operación."],
      ["Prepare independent alternatives for people, technology, data and suppliers.", "Preparar alternativas independientes para personas, tecnología, datos y proveedores."],
      ["Detect deterioration and switch deliberately to degraded operation.", "Detectar deterioro y pasar deliberadamente a operación degradada."],
      ["Exercise recovery and adapt the system using observed weaknesses.", "Ensayar recuperación y adaptar el sistema según debilidades observadas."]
    ]
  ),
  "backup-disaster-recovery": h(
    "Backups create recoverable copies according to recovery point objectives, while disaster recovery restores the technology needed to meet recovery time objectives. Data is copied on a schedule or continuously, retained in several versions and stored in a location or account that ordinary administrators and malware cannot alter. Application-consistent backups preserve related databases and transactions rather than copying files in an unusable state.\n\nA recovery runbook rebuilds infrastructure, restores identity and keys, loads data and validates applications in dependency order. Tests measure actual time, data loss and failure points. Replication alone is not a backup because corruption or deletion can replicate immediately; a successful backup job is not proof until restoration has been completed.",
    "Las copias crean versiones recuperables según objetivos de punto de recuperación, mientras la recuperación ante desastres restaura la tecnología necesaria dentro del tiempo objetivo. Los datos se copian periódicamente o de forma continua, se conservan varias versiones y se guardan en una ubicación o cuenta que administradores ordinarios y malware no pueden alterar. Las copias coherentes con la aplicación preservan bases de datos y transacciones relacionadas en vez de copiar ficheros en un estado inutilizable.\n\nUn procedimiento reconstruye infraestructura, restaura identidad y claves, carga datos y valida aplicaciones según dependencias. Las pruebas miden tiempo real, pérdida de datos y puntos de fallo. La replicación no es por sí sola una copia porque corrupción o borrado se replican; una tarea correcta tampoco demuestra nada hasta completar una restauración.",
    [
      ["Set recovery point and recovery time objectives per service.", "Fijar objetivos de punto y tiempo de recuperación por servicio."],
      ["Create versioned, isolated and immutable copies with known ownership.", "Crear copias versionadas, aisladas e inmutables con responsable conocido."],
      ["Restore infrastructure, identity, keys, data and applications in order.", "Restaurar infraestructura, identidad, claves, datos y aplicaciones en orden."],
      ["Measure end-to-end restoration and correct every failed dependency.", "Medir la restauración completa y corregir cada dependencia fallida."]
    ]
  ),
  "business-continuity": h(
    "Business continuity keeps priority activities operating when normal resources are unavailable. A business impact analysis identifies products and services, maximum tolerable disruption, time-sensitive obligations and dependencies on staff, sites, technology, information and suppliers. Strategies then provide alternate locations, manual procedures, substitute suppliers, cross-trained staff and communication arrangements.\n\nA continuity plan contains triggers, decision authority, contact information, workarounds and criteria for returning to normal. Exercises test realistic shortages and conflicting priorities, not just whether people can read the document. Technology recovery supports continuity, but the business may need to operate before every system is restored.",
    "La continuidad de negocio mantiene actividades prioritarias cuando los recursos normales no están disponibles. Un análisis de impacto identifica productos y servicios, interrupción máxima tolerable, obligaciones urgentes y dependencias de personal, instalaciones, tecnología, información y proveedores. Las estrategias aportan ubicaciones alternativas, procedimientos manuales, proveedores sustitutos, personal polivalente y comunicaciones.\n\nEl plan contiene desencadenantes, autoridad de decisión, contactos, alternativas y criterios para volver a la normalidad. Los ejercicios prueban escasez y prioridades en conflicto, no solo si alguien puede leer el documento. La recuperación tecnológica apoya la continuidad, pero el negocio puede necesitar operar antes de restaurar todos los sistemas.",
    [
      ["Identify priority activities and maximum tolerable disruption.", "Identificar actividades prioritarias e interrupción máxima tolerable."],
      ["Map dependencies on people, premises, information, technology and suppliers.", "Representar dependencias de personas, instalaciones, información, tecnología y proveedores."],
      ["Prepare practical workarounds and authority to activate them.", "Preparar alternativas prácticas y autoridad para activarlas."],
      ["Exercise constrained operations and improve plans from observed results.", "Ensayar operaciones limitadas y mejorar planes según resultados observados."]
    ]
  ),
  "ai-security": h(
    "AI system security covers the full path from data and model creation to inference and action. Training data is collected, filtered and versioned; code and model artefacts move through a supply chain; the deployed model receives prompts and may call tools, retrieve documents or write to other systems. Each boundary introduces distinct risks such as poisoned data, stolen models, prompt injection, unsafe generated content and excessive tool authority.\n\nDefences separate untrusted instructions from trusted policy, restrict tools to narrow permissions, validate retrieved content and outputs, and monitor unusual model or agent behaviour. Human approval is retained for high-impact actions. Evaluation includes adversarial testing and misuse cases, but production controls remain necessary because model behaviour is probabilistic and the surrounding data changes.",
    "La seguridad de sistemas de IA cubre todo el recorrido desde los datos y la creación del modelo hasta la inferencia y la acción. Los datos de entrenamiento se recogen, filtran y versionan; el código y los artefactos del modelo atraviesan una cadena de suministro; y el modelo desplegado recibe instrucciones y puede llamar a herramientas, recuperar documentos o escribir en otros sistemas. Cada límite introduce riesgos distintos, como datos envenenados, robo de modelos, inyección de instrucciones, contenido inseguro y autoridad excesiva de herramientas.\n\nLas defensas separan instrucciones no fiables de políticas de confianza, limitan las herramientas a permisos estrechos, validan contenido recuperado y salidas y monitorizan comportamiento anómalo. Las acciones de alto impacto mantienen aprobación humana. La evaluación incluye pruebas adversarias y casos de abuso, pero hacen falta controles en producción porque el comportamiento es probabilístico y los datos cambian.",
    [
      ["Control provenance and integrity of training, retrieval and evaluation data.", "Controlar procedencia e integridad de datos de entrenamiento, recuperación y evaluación."],
      ["Protect model, code, prompts and deployment artefacts through the supply chain.", "Proteger modelo, código, instrucciones y artefactos durante la cadena de suministro."],
      ["Treat external content as untrusted and restrict agent tool permissions.", "Tratar contenido externo como no fiable y limitar permisos de herramientas del agente."],
      ["Evaluate, monitor and require human approval for consequential actions.", "Evaluar, monitorizar y exigir aprobación humana para acciones relevantes."]
    ]
  ),
  "post-quantum": h(
    "Post-quantum migration begins by discovering where cryptography is used: protocols, certificates, libraries, hardware, embedded devices, signed updates and long-lived encrypted data. Each use is classified by algorithm, key size, data lifetime and replacement difficulty. Systems that protect information for many years may be exposed to harvest-now-decrypt-later attacks even before a cryptographically relevant quantum computer exists.\n\nCrypto-agile designs separate algorithms from business logic and allow new certificates, key sizes and message formats to be introduced without replacing the whole product. Organisations test standardised post-quantum algorithms in hybrid or controlled deployments, measure performance and interoperability, and plan supplier and certificate transitions. Migration is phased because legacy systems and protocols cannot all change at once.",
    "La migración poscuántica comienza descubriendo dónde se usa criptografía: protocolos, certificados, bibliotecas, hardware, dispositivos embebidos, actualizaciones firmadas y datos cifrados de larga duración. Cada uso se clasifica por algoritmo, tamaño de clave, vida de los datos y dificultad de sustitución. La información que debe protegerse durante años puede estar expuesta a ataques de recopilar ahora y descifrar después incluso antes de existir un ordenador cuántico criptográficamente relevante.\n\nLos diseños criptoágiles separan algoritmos de la lógica de negocio y permiten introducir nuevos certificados, tamaños de clave y formatos sin sustituir el producto completo. Se prueban algoritmos poscuánticos normalizados en despliegues híbridos o controlados, se mide rendimiento e interoperabilidad y se planifican transiciones de proveedores y certificados. La migración es gradual porque los sistemas heredados no pueden cambiar todos a la vez.",
    [
      ["Inventory algorithms, protocols, keys and protected-data lifetimes.", "Inventariar algoritmos, protocolos, claves y vida de los datos protegidos."],
      ["Prioritise long-lived confidentiality and hard-to-replace systems.", "Priorizar confidencialidad de larga duración y sistemas difíciles de sustituir."],
      ["Introduce crypto-agility and test standardised post-quantum options.", "Introducir criptoagilidad y probar opciones poscuánticas normalizadas."],
      ["Migrate certificates, suppliers and protocols through controlled phases.", "Migrar certificados, proveedores y protocolos mediante fases controladas."]
    ]
  ),
  "iot-edge": h(
    "IoT and edge systems collect data and act close to the physical environment through constrained devices, gateways and remote platforms. A device receives a unique identity at manufacture or enrolment, authenticates to a gateway or cloud service and exchanges telemetry and commands. Secure boot verifies firmware, signed updates maintain it and hardware protections guard keys. Gateways aggregate protocols, enforce network boundaries and continue limited operation when connectivity is lost.\n\nThe lifecycle is often longer than ordinary IT, so ownership, update support and end-of-life matter from the beginning. Default credentials, unnecessary services and direct internet exposure create persistent attack paths. Inventory and segmentation prevent an unmanaged sensor from becoming a route to more critical systems.",
    "Los sistemas IoT y de borde recogen datos y actúan cerca del entorno físico mediante dispositivos limitados, pasarelas y plataformas remotas. El dispositivo recibe una identidad única durante fabricación o alta, se autentica ante una pasarela o nube e intercambia telemetría y órdenes. El arranque seguro verifica firmware, las actualizaciones firmadas lo mantienen y las protecciones de hardware custodian claves. Las pasarelas agregan protocolos, aplican límites de red y mantienen operación limitada cuando se pierde conectividad.\n\nEl ciclo de vida suele superar al de TI, por lo que responsable, soporte de actualizaciones y fin de vida deben definirse desde el principio. Credenciales predeterminadas, servicios innecesarios y exposición directa crean rutas persistentes. El inventario y la segmentación evitan que un sensor sin gestionar se convierta en vía hacia sistemas críticos.",
    [
      ["Provision a unique device identity and protected root of trust.", "Aprovisionar una identidad única y una raíz de confianza protegida."],
      ["Authenticate telemetry and commands through a controlled gateway or service.", "Autenticar telemetría y órdenes mediante una pasarela o servicio controlado."],
      ["Use secure boot, signed updates and minimal exposed services.", "Usar arranque seguro, actualizaciones firmadas y servicios expuestos mínimos."],
      ["Track ownership, support status and safe decommissioning throughout the lifecycle.", "Rastrear responsable, soporte y retirada segura durante todo el ciclo."]
    ]
  ),
  "space-5g-digital-twins": h(
    "Space systems, 5G networks and digital twins combine distributed control with models of physical reality. Satellites rely on command links, ground stations, timing and long-lived onboard software; 5G separates radio, transport and virtualised core functions governed through software; a digital twin ingests sensor data to estimate or influence the state of a physical asset. In all three, integrity and timing can matter as much as confidentiality.\n\nSecurity verifies command authority, segments management planes, protects software and model supply chains and detects disagreement between expected and observed physical behaviour. Redundant timing, communications and ground or edge control preserve service during disruption. A twin is treated as a decision-support system whose data, assumptions and update history must be validated before actions are applied to the real asset.",
    "Los sistemas espaciales, las redes 5G y los gemelos digitales combinan control distribuido con modelos de la realidad física. Los satélites dependen de enlaces de mando, estaciones terrestres, sincronización y software embarcado de larga vida; 5G separa radio, transporte y núcleo virtualizado gobernado por software; y un gemelo ingiere sensores para estimar o influir en el estado de un activo físico. En los tres, integridad y tiempo pueden importar tanto como confidencialidad.\n\nLa seguridad verifica autoridad de mando, segmenta planos de administración, protege cadenas de software y modelos y detecta discrepancias entre comportamiento esperado y observado. La redundancia de tiempo, comunicaciones y control terrestre o de borde mantiene el servicio. Un gemelo se trata como apoyo a decisiones cuyos datos, supuestos e historial deben validarse antes de actuar sobre el activo real.",
    [
      ["Separate mission, management, data and physical-control trust boundaries.", "Separar límites de confianza de misión, administración, datos y control físico."],
      ["Authenticate commands and protect timing, software and model provenance.", "Autenticar órdenes y proteger sincronización, software y procedencia de modelos."],
      ["Compare predicted state with independent physical observations.", "Comparar el estado previsto con observaciones físicas independientes."],
      ["Maintain alternate communications and safe local control during disruption.", "Mantener comunicaciones alternativas y control local seguro durante interrupciones."]
    ]
  )
};
